// Auto-generated: quiz content for Cours18 — translations can be added per-locale.
// Structural data arrays (DEGREES, MODES, etc.) remain in the component for now.

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours18Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Définition du motif
  { q: "Qu'est-ce qu'un motif musical ?", opts: ["Un accord de 4 sons", "La plus petite unité musicale distincte, immédiatement reconnaissable — fil conducteur du discours", "Une gamme complète", "Un accord de dominante"], a: 1, fb: "Le motif est la plus petite cellule musicale autonome et distincte. Il contient une identité rythmique et/ou mélodique reconnaissable, qui sera répétée et transformée pour construire un discours musical cohérent. Beethoven construit toute sa 5e Symphonie depuis un motif de 4 notes seulement." },
  { q: "Quel est le rôle principal du motif dans une composition ?", opts: ["Fixer le tempo", "Servir de fil conducteur — répété et transformé, il donne cohérence et direction au discours musical", "Indiquer la tonalité", "Déterminer le nombre de mesures"], a: 1, fb: "Le motif est le fil conducteur. Sa répétition (stricte ou transformée) crée la cohérence : l'auditeur reconnaît l'idée même transformée, et suit ainsi le discours musical. Sans motif directeur, une succession d'accords est 'hors sol' — une liste sans direction." },
  { q: "Quelle différence entre 'musique de support' et 'musique de discours' ?", opts: ["La musique de support est plus rapide", "La musique de support accompagne une action extérieure ; la musique de discours développe ses propres idées musicales de façon autonome", "La musique de discours est plus courte", "Il n'y a aucune différence"], a: 1, fb: "La musique de support (film, ballet, publicité) sert une action extérieure — sa structure peut être fragmentée selon la narration. La musique de discours (sonate, fugue, standard jazz) développe ses propres idées de façon logique, indépendamment de tout contexte extra-musical." },
  { q: "Le 'paradoxe de la répétition' en composition musicale signifie que :", opts: ["Il ne faut jamais répéter", "La répétition est nécessaire pour la cohérence, mais dangereuse si elle est trop pure — la monotonie menace", "Il faut toujours répéter exactement", "La répétition est uniquement rythmique"], a: 1, fb: "Paradoxe central : sans répétition, pas de cohérence (l'auditeur ne reconnaît rien) ; avec trop de répétition identique, la monotonie s'installe. La solution : répéter en transformant. La variété dans la répétition est l'art même du développement motivique." },
  { q: "Les trois étapes de la vie d'un motif sont :", opts: ["Introduction, développement, coda", "Présentation → Répétition → Évolution", "Exposition, fugue, réexposition", "Motif, thème, période"], a: 1, fb: "Un motif suit trois étapes rhétoriques : Présentation (établir l'identité), Répétition (ancrer le motif dans l'oreille), Évolution (transformer, développer, combiner). Cette trajectoire s'applique à l'échelle de la phrase (8 mesures), du mouvement et de l'œuvre entière." },

  // Les 5 éléments constitutifs
  { q: "Combien d'éléments constitutifs définissent un motif ?", opts: ["2 (mélodie et rythme)", "3 (mélodie, rythme, harmonie)", "5 (intervalles, rythme, harmonie, accompagnement, dynamique)", "7 (un par note)"], a: 2, fb: "Cinq éléments constituent un motif : (1) intervalles (contour mélodique), (2) rythme (schéma de durées), (3) harmonie (accords de soutien), (4) accompagnement (texture), (5) dynamique (nuances et articulation). Chaque élément peut être modifié indépendamment lors du développement." },
  { q: "Parmi les 5 éléments d'un motif, lequel est souvent le plus immédiatement reconnaissable ?", opts: ["La mélodie (intervalles)", "Le rythme — son schéma est souvent identifiable même si les hauteurs changent", "L'harmonie", "La dynamique"], a: 1, fb: "Le rythme est souvent l'élément le plus distinctif. Dans le motif ta-ta-ta-TAA de Beethoven (3 croches + noire), on le reconnaît même transposé dans une autre tonalité ou joué par un instrument différent. Le rythme est l'ADN temporel du motif." },
  { q: "L'élément 'accompagnement' d'un motif désigne :", opts: ["La mélodie principale", "La texture qui entoure le motif : arpèges, accords plaqués, ligne de basse indépendante", "Les nuances dynamiques", "Le tempo"], a: 1, fb: "L'accompagnement est la texture musicale qui entoure le motif mélodique. Un même motif peut sonner radicalement différent selon qu'il est accompagné d'arpèges (légèreté), d'accords plaqués (solidité) ou d'une ligne de basse en contrepoint (richesse polyphonique)." },
  { q: "L'élément 'dynamique' d'un motif inclut :", opts: ["Les hauteurs de notes uniquement", "Les nuances (forte/piano), l'articulation (legato/staccato) et l'attaque — l'expression physique du motif", "Le nombre de répétitions", "La tonalité du morceau"], a: 1, fb: "La dynamique regroupe les nuances (forte, piano, crescendo), l'articulation (legato, staccato, accent), et le type d'attaque. Même motif joué pianissimo legato vs fortissimo staccato : deux caractères entièrement différents, sans changer une note." },
  { q: "Pourquoi les intervalles sont-ils un élément constitutif du motif ?", opts: ["Car ils fixent le tempo", "Car les sauts mélodiques caractéristiques (tierce, quinte, triton) créent l'identité mélodique distinctive du motif", "Car ils indiquent la mesure", "Car ils sont toujours les mêmes dans tous les motifs"], a: 1, fb: "Les intervalles sont l'empreinte mélodique du motif. La chute de tierce mineure (Sol–Mib) dans le motif de Beethoven est immédiatement reconnaissable. Un motif construit sur un triton sonnera tendu ; sur une tierce majeure, brillant. Les intervalles fixent le caractère mélodique." },

  // Exemples
  { q: "Quel motif Beethoven utilise dans sa 5e Symphonie (1808) ?", opts: ["4 notes descendantes par demi-tons", "3 notes répétées + une chute de tierce mineure (Sol–Sol–Sol–Mib, ta-ta-ta-TAA)", "Un arpège de Do majeur", "Une gamme ascendante"], a: 1, fb: "Sol–Sol–Sol–Mib : 3 notes répétées identiquement + chute de tierce mineure. Ce motif est le germe de toute la 5e Symphonie. Beethoven le fragmente, le transpose, l'augmente dans les 4 mouvements — démonstration absolue de l'économie de moyens." },
  { q: "Qu'est-ce qu'un 'leitmotiv' chez Wagner ?", opts: ["Un tempo particulier", "Un motif récurrent associé à un personnage ou une idée dramatique — transformé selon le contexte", "Un accord de dominante", "Une fugue pour orchestre"], a: 1, fb: "Wagner associe dans ses opéras un motif musical (leitmotiv) à chaque personnage, concept ou objet dramatique. Le motif de l'épée de Siegfried revient transformé selon la situation — glorieux dans les moments de triomphe, sombre dans les moments de danger. C'est la forme motivique étendue à l'échelle d'un opéra entier." },
  { q: "Comment John Williams hérite-t-il de la technique de Wagner dans Star Wars ?", opts: ["Il utilise les mêmes harmonies", "Il associe un leitmotiv à chaque personnage (thème de la Force, marche impériale) qu'il transforme selon le contexte dramatique", "Il copie les rythmes de Wagner", "Il utilise les mêmes instruments"], a: 1, fb: "Williams hérite directement de Wagner : chaque personnage a son motif. Le thème de la Force — calme et lumineux — devient la marche impériale pour Dark Vador, avec le même contour mélodique mais une harmonisation radicalement différente (mineur, cuivres, dynamique forte). Même technique, un siècle plus tard." },
  { q: "Ce qui rend le motif de Beethoven (5e Symphonie) si efficace est :", opts: ["Sa longueur — plus de 8 notes", "Sa brièveté et sa distinctivité : 4 notes seulement, avec un rythme et un intervalle immédiatement mémorisables", "Sa complexité harmonique", "Son orchestration rare"], a: 1, fb: "La force du motif est son économie. 4 notes : 3 répétées (l'insistance) + 1 chute de tierce mineure (la résolution descendante). Ce dépouillement le rend universellement mémorable et infiniment transformable. Beethoven en tire 20 minutes de symphonie — économie maximale, expressivité maximale." },
  { q: "La technique du leitmotiv est notamment utilisée par :", opts: ["Bach dans ses fugues", "Wagner et, plus tard, John Williams dans ses musiques de film", "Chopin dans ses nocturnes", "Debussy dans ses préludes"], a: 1, fb: "Wagner développe le leitmotiv dans ses opéras (L'Anneau du Nibelung, Tristan und Isolde). Cette technique passe dans le cinéma via Korngold, Herrmann et surtout John Williams — qui reconnait ouvertement sa dette envers Wagner dans Star Wars et les séries qui suivent." },

  // Famille A — Harmonie et accompagnement
  { q: "La famille A (harmonie et accompagnement) est appliquée en premier car :", opts: ["Elle est plus facile", "C'est la transformation la moins radicale — l'identité mélodique et rythmique du motif reste intacte", "Elle donne le meilleur résultat", "Elle est la plus rapide à réaliser"], a: 1, fb: "En modifiant l'harmonie ou la texture d'accompagnement, on transforme la 'couleur' du motif sans toucher à son identité mélodie-rythme. L'auditeur reconnaît pleinement le motif — le changement est subtil. C'est pourquoi cette famille est appliquée en premier : effet remarquable, risque de perte d'identité minimal." },
  { q: "La 'substitution harmonique' dans le développement motivique consiste à :", opts: ["Changer le motif mélodique", "Remplacer un accord par un autre de même fonction ou couleur (I → VI, V7 → SubV) sous le même motif", "Changer la tonalité du morceau", "Supprimer des accords"], a: 1, fb: "La substitution harmonique change les accords qui soutiennent le motif sans toucher aux notes du motif lui-même. Remplacer I par VI (substitution diatonique) donne une couleur plus douce ; V7 par SubV (substitution tritonique) produit une basse chromatique. Le motif reste reconnaissable, la couleur change totalement." },
  { q: "Transformer l'accompagnement en 'arpèges' plutôt qu'en 'accords plaqués' modifie :", opts: ["Les notes du motif", "La texture — la façon dont les accords sont déployés dans le temps, créant légèreté ou mouvement", "La tonalité", "Le rythme du motif"], a: 1, fb: "Les arpèges brisent les accords en notes successives — ce qui crée du mouvement et de la légèreté (Chopin). Les accords plaqués créent solidité et impact (Beethoven). Même harmonie, même motif mélodique, textures totalement différentes. La transformation d'accompagnement est l'une des plus fréquentes en composition." },
  { q: "Le 'contrepoint' comme technique de développement motivique consiste à :", opts: ["Répéter le motif deux fois", "Ajouter une voix indépendante qui répond, imite ou contraste avec le motif — enrichissant la polyphonie", "Changer le tempo", "Inverser les intervalles"], a: 1, fb: "Le contrepoint ajoute une ou plusieurs voix qui dialoguent avec le motif principal. Cette voix peut l'imiter (canon), lui répondre en mouvement contraire, ou l'accompagner en sixte parallèle. L'œuvre devient plus dense sans modifier le motif — c'est l'enrichissement par addition, pas par transformation." },
  { q: "La 'ligne de basse' comme développement motivique signifie :", opts: ["Jouer le motif à la basse", "Transformer la basse en contrepoint mélodique indépendant — tierce, sixte ou mouvement contraire — qui dialogue avec le motif", "Supprimer la basse", "Doubler la basse à l'octave"], a: 1, fb: "Au lieu de simplement doubler la basse harmonique, on lui donne un contour mélodique propre — une ligne de basse en mouvement contraire au motif, ou en tierce/sixte parallèle. Cette technique est très présente chez Bach (chorals) et Beethoven (sonates) : elle enrichit la texture sans altérer le motif." },

  // Famille B — Dynamique
  { q: "Modifier les 'nuances' d'un motif (forte → piano) transforme :", opts: ["Les hauteurs de notes", "L'intensité et le caractère expressif — même mélodie, impact émotionnel radicalement différent", "Le rythme", "La tonalité"], a: 1, fb: "Le même motif joué fortissimo est menaçant ou triomphal ; pianissimo, il devient mystérieux ou tendre. Beethoven exploite systématiquement cette dichotomie : il présente son motif fortissimo, puis le répète pianissimo — double affirmation, double caractère. Les nuances transforment le sens sans toucher aux notes." },
  { q: "Transposer un motif d'une octave vers le haut produit :", opts: ["Le même effet qu'à l'octave inférieure", "Luminosité, urgence et clarté — la tessiture aiguë est perçue comme plus brillante et intense", "Un ralentissement perçu", "Un changement de tonalité"], a: 1, fb: "La tessiture aiguë crée luminosité et tension (perçue comme plus urgente psychologiquement). L'octave grave crée profondeur, gravité, autorité. Beethoven utilise cette transformation de tessiture systématiquement dans ses développements — même motif, registres différents, effets dramatiques contrastants." },
  { q: "Passer d'un jeu legato à un jeu staccato sur le même motif :", opts: ["Ralentit le motif", "Change l'articulation — le caractère devient incisif, léger ou nerveux selon le contexte, sans toucher aux hauteurs", "Modifie les intervalles", "Change l'harmonie"], a: 1, fb: "Legato = notes liées, flux continu, caractère lyrique ou doux. Staccato = notes détachées, caractère vif, léger ou incisif. Le même motif en legato semble nostalgique ; en staccato, espiègle ou urgent. L'articulation est l'un des paramètres les plus fins et expressifs du développement dynamique." },
  { q: "Changer le 'timbre' dans un développement motivique signifie :", opts: ["Changer le compositeur", "Confier le même motif à un instrument différent (violons → cuivres, piano → orchestre) — même mélodie, couleur instrumentale radicalement différente", "Changer la tonalité", "Modifier le rythme"], a: 1, fb: "Le même motif aux violons semble lyrique ; aux cuivres, héroïque ; à la flûte, aérien ; au piano fortissimo, percutant. Le timbre est la 'voix' de l'instrument. Dans les développements symphoniques, Beethoven passe le même motif à travers différentes familles orchestrales — transformation pure de timbre, pas de notes." },

  // Famille C — Transformations mélodiques
  { q: "Le 'renversement' (inversion des intervalles) d'un motif consiste à :", opts: ["Jouer le motif à l'envers", "Inverser chaque intervalle : une montée de tierce devient une descente de tierce (et vice versa)", "Répéter le motif deux fois plus vite", "Transposer d'une octave"], a: 1, fb: "Le renversement mirror chaque intervalle. Sol–Sol–Sol–Mib (chute de tierce mineure) devient Sol–Sol–Sol–Sib (montée de tierce mineure). Le contour rythmique reste identique ; le profil mélodique est inversé. Technique fréquente dans les fugues de Bach et les développements de Beethoven." },
  { q: "Le 'rétrograde' d'un motif est :", opts: ["Le motif joué plus lentement", "Le motif joué à l'envers — de la dernière note à la première", "Le motif transposé à l'octave", "Le motif répété deux fois"], a: 1, fb: "Le rétrograde inverse l'ordre des notes : Mib–Sol–Sol–Sol est le rétrograde de Sol–Sol–Sol–Mib (Beethoven). Technique utilisée par Bach dans les canons, par Beethoven et par les sérialistes. Elle peut sembler méconnaissable à l'oreille mais maintient une cohérence logique avec le matériel original." },
  { q: "Ajouter des 'notes de passage' à un motif :", opts: ["Supprime le motif", "Enrichit le contour mélodique en comblant les sauts — le motif original reste reconnaissable, la mélodie devient plus fluide", "Change le rythme", "Change la tonalité"], a: 1, fb: "Les notes de passage remplissent les intervalles du motif. Un saut de tierce (Do–Mi) devient une gamme descendante (Do–Ré–Mi). Le contour rythmique peut rester identique. Le motif est plus riche mélodiquement, moins 'anguleux', mais son identité de départ reste perceptible." },
  { q: "La 'transformation non rythmique' d'un motif signifie :", opts: ["Garder le rythme identique mais modifier les hauteurs selon la gamme (marche harmonique ou transposition)", "Changer uniquement le rythme", "Supprimer toutes les notes", "Inverser le motif"], a: 0, fb: "La transformation non rythmique conserve le schéma rythmique du motif mais fait glisser les hauteurs selon la gamme (marche tonale) ou par transposition exacte (marche réelle). Le rythme — souvent l'identité la plus forte — reste reconnaissable ; les hauteurs varient. C'est la marche harmonique ou séquence." },
  { q: "Pourquoi le renversement et le rétrograde sont-ils des transformations 'de la famille C' ?", opts: ["Parce qu'ils sont les plus simples", "Parce qu'ils transforment le contour mélodique sans nécessairement toucher au rythme — hauteurs modifiées, structure temporelle préservée", "Parce qu'ils s'appliquent après les altérations rythmiques", "Parce qu'ils ne modifient que l'harmonie"], a: 1, fb: "Renversement et rétrograde modifient les hauteurs tout en maintenant (souvent) la structure rythmique. Ils appartiennent aux transformations mélodiques (famille C). Ce sont des transformations plus radicales que la famille A (harmonie) mais moins radicales que la famille D (altérations rythmiques)." },
  { q: "L'omission d'une note d'un motif :", opts: ["Détruit le motif entièrement", "Allège le motif — le contour général peut rester reconnaissable, créant une version réduite ou fragmentée", "N'est jamais utilisée en composition", "Doit toujours être compensée par une autre note"], a: 1, fb: "Omettre une note crée une version 'allégée' du motif — technique de liquidation progressive (terme de Schoenberg). Le motif perd progressivement ses traits distinctifs. Beethoven utilise cette technique en fin de développement : le motif se fragmente jusqu'à se dissoudre dans la cadence finale." },

  // Famille D — Altérations rythmiques
  { q: "L'augmentation d'un motif consiste à :", opts: ["Jouer le motif plus fort", "Doubler (ou tripler) la durée de chaque note — le motif ralentit, prend une ampleur solennelle", "Transposer d'une octave", "Inverser les intervalles"], a: 1, fb: "L'augmentation double chaque durée : une croche devient une noire, une noire devient une blanche. Le motif est le même mais s'étire dans le temps — effet de ralenti, de solennité, de grandeur. Beethoven l'utilise dans les développements pour créer un sentiment d'inéluctabilité." },
  { q: "La diminution d'un motif consiste à :", opts: ["Jouer le motif moins fort", "Diviser la durée de chaque note — le motif s'accélère, devient nerveux ou urgent", "Supprimer des notes", "Inverser le motif"], a: 1, fb: "La diminution divise chaque durée : une noire devient une croche, une croche une double croche. Le motif s'accélère — effet de tension montante, d'impatience, d'urgence. Technique fréquente dans les développements de fugues (Bach) et les sections de liquidation de Beethoven." },
  { q: "Le changement de carrure (3/4 → 4/4) transforme un motif en :", opts: ["Lui ajoutant des notes", "Changeant son contexte métrique — le même motif dans un mètre différent crée un sentiment de légèreté, déséquilibre ou nouvelle énergie", "Modifiant ses hauteurs", "Doublant sa durée"], a: 1, fb: "Transposer un motif de 4/4 en 3/4 lui donne une allure de valse ; de 3/4 en 2/4, une énergie de marche. La barre de mesure se déplace par rapport aux notes — des accents tombent à d'autres endroits. Le motif est identique, mais son rapport au temps a changé. Chopin utilise cette technique dans son Scherzo n°2." },
  { q: "Pourquoi les altérations rythmiques sont-elles appliquées en dernier ?", opts: ["Parce qu'elles sont plus difficiles à écrire", "Parce que le rythme est souvent l'élément le plus distinctif du motif — le modifier est le changement le plus radical, risquant de rendre le motif méconnaissable", "Parce qu'elles nécessitent un orchestre", "Parce qu'elles sont les moins expressives"], a: 1, fb: "Le rythme est souvent l'ADN le plus robuste d'un motif — on reconnaît le ta-ta-ta-TAA de Beethoven même transposé dans une autre tonalité. Toucher au rythme, c'est risquer de perdre l'identité du motif. C'est pourquoi les altérations rythmiques viennent en dernier : elles ont le plus grand pouvoir transformateur — et le plus grand risque." },
  { q: "La 'dérégulation' rythmique d'un motif consiste à :", opts: ["Regulariser les syncopes", "Transformer des temps forts en syncopes — déplacer les accents du motif pour créer tension ou surprise rythmique", "Doubler la durée des notes", "Changer le tempo"], a: 1, fb: "La dérégulation crée des syncopes là où le motif original avait des temps forts. L'effet est de déstabilisation rythmique — l'oreille attendait un accent à un endroit, il arrive décalé. Technique très présente en jazz (off-beat phrasing) et dans les développements beethovéniens." },

  // Ordre d'application
  { q: "L'ordre correct d'application des 4 familles est :", opts: ["D → C → B → A (rythme en premier)", "A → B → C → D (harmonie en premier, rythme en dernier)", "C → A → D → B (mélodique en premier)", "Il n'y a pas d'ordre défini"], a: 1, fb: "L'ordre A–B–C–D va du moins au plus radical : A (harmonie/accompagnement) transforme le moins l'identité du motif ; D (rythme) la transforme le plus. On commence par les transformations qui laissent le motif pleinement reconnaissable, pour aller progressivement vers des transformations plus profondes." },
  { q: "Si on veut appliquer une transformation qui laisse le motif pleinement identifiable, on utilise :", opts: ["La famille D (altérations rythmiques)", "La famille A (harmonie et accompagnement) — le contour mélodique et le rythme restent intacts", "La famille C (transformations mélodiques)", "La famille B et D ensemble"], a: 1, fb: "La famille A est la moins radicale : changer l'harmonie ou la texture (arpèges, contrepoint, substitution) laisse le motif entièrement reconnaissable. La mélodie et le rythme — ses deux traits les plus identifiables — restent intacts. C'est le 'recoloriage' du motif, pas sa transformation." },
  { q: "Combien de familles de techniques de développement motivique existe-t-il ?", opts: ["3", "4", "5", "7"], a: 1, fb: "Il y a 4 familles : A (harmonie et accompagnement), B (arrangement dynamique), C (transformations mélodiques), D (altérations rythmiques). Chaque famille regroupe des techniques d'un degré de radicalité similaire et s'applique dans cet ordre — du moins au plus transformateur." },

  // Beethoven biographique
  { q: "En quelle année Beethoven compose-t-il sa 5e Symphonie ?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "La 5e Symphonie de Beethoven est achevée en 1808 (dédiée au prince Lobkowitz et au comte Razumovsky). La même année sort la 6e Symphonie (Pastorale). Beethoven est alors en pleine période 'héroïque' — il est également sourd depuis plusieurs années, ce qui rend sa maîtrise motivique d'autant plus remarquable." },
  { q: "Beethoven est souvent associé à quel principe esthétique ?", opts: ["L'ornementation baroque", "L'économie de moyens — construire le maximum à partir du minimum de matériel motivique", "La mélodie opératique", "L'improvisation modale"], a: 1, fb: "L'économie de moyens est le principe beethovénien par excellence : en tirer le maximum du minimum. 4 notes génèrent une symphonie. Cette approche contrastait avec le style galant et ornemental de ses prédécesseurs. Pour Beethoven, la richesse n'est pas dans la quantité de matériel, mais dans la profondeur de son développement." },
  { q: "À quelle époque compositionnelle appartient Beethoven ?", opts: ["Baroque (1600–1750)", "Classicisme (1750–1820) — avec un pied dans le Romantisme", "Romantisme tardif (1850–1900)", "Impressionnisme (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) est une charnière : ses premières œuvres s'inscrivent dans le classicisme viennois (Haydn, Mozart), mais ses œuvres tardives (Quatuors op.132, Sonate op.111, 9e Symphonie) anticipent le Romantisme et même le XXe siècle. Il transcende les catégories époque." },
  { q: "Schoenberg a notamment analysé la technique de Beethoven dans :", opts: ["L'Art de la fugue", "Fundamentals of Musical Composition — traité formalisant la phrase, le motif, la période et les formes beethovéniennes", "Le Clavecin bien tempéré", "Traité d'orchestration de Berlioz"], a: 1, fb: "Schoenberg rédige Fundamentals of Musical Composition à UCLA dans les années 1930–40 (publié posthumement en 1967). Son traité analyse systématiquement la phrase et le développement motivique de Beethoven — paradoxalement, Schoenberg est aussi le père du dodécaphonisme, qui abolit la tonalité beethovénienne." },

  // Applications
  { q: "Comment reconnaît-on un bon motif de départ ?", opts: ["Il doit être très long", "Il est court, distinctif, mémorisable, et suffisamment flexible pour être transformé de multiples façons", "Il doit contenir toutes les notes de la gamme", "Il doit éviter les dissonances"], a: 1, fb: "Un bon motif combine brièveté (mémorisable), distinctivité (reconnaissable parmi d'autres) et flexibilité (transformable). Sol–Sol–Sol–Mib satisfait ces trois critères. Un motif trop complexe est difficile à transformer ; trop simple, il devient monotone. L'équilibre est l'art du compositeur." },
  { q: "Quelle est l'erreur la plus commune avec un motif en composition ?", opts: ["L'utiliser trop souvent", "Répéter le motif identiquement trop de fois de suite sans transformation — la monotonie s'installe rapidement", "Le transposer dans d'autres tonalités", "L'utiliser dans différentes familles instrumentales"], a: 1, fb: "La répétition pure est la tentation et le piège. Un motif répété identiquement plus de deux fois perd son pouvoir d'attraction. L'oreille attend de la variété. L'art est de maintenir la reconnaissance (cohérence) tout en renouvelant (variété) — c'est le paradoxe de la répétition." },
  { q: "Quel est l'effet d'une 'marche harmonique' dans le développement d'un motif ?", opts: ["Supprimer le motif", "Répéter le motif à des degrés successifs de la gamme — l'effet est d'élargissement tonal progressif", "Changer le tempo uniquement", "Arrêter le discours musical"], a: 1, fb: "La marche harmonique répète le motif à chaque degré de la gamme (I, II, III, IV...). L'auditeur perçoit à la fois la cohérence (même motif) et le mouvement (changement de hauteur à chaque répétition). Effet de 'progression' ou d''escalade' très efficace en développement." },
  { q: "En improvisation jazz, comment la connaissance du développement motivique améliore-t-elle le jeu ?", opts: ["Elle permet de jouer plus de notes", "Elle donne des outils pour construire un discours cohérent — exposer une idée, la répéter/transformer, la développer vers un climax, conclure", "Elle force à rester dans la gamme pentatonique", "Elle remplace la connaissance de la grille harmonique"], a: 1, fb: "Un improvisateur qui maîtrise le développement motivique construit un 'discours' plutôt qu'une suite de notes. Il expose un motif (quelques notes), le répète et le transforme (famille A, B, C ou D), crée un climax, puis conclut. L'auditeur suit l'histoire. C'est la différence entre improviser 'dans' la grille et improviser 'à travers' la grille." },
  { q: "La 'liquidation' d'un motif en fin de phrase (Schoenberg) produit :", opts: ["Un silence", "Une dissolution progressive du motif — il perd ses traits distinctifs un par un, signalant que la cadence approche", "Une modulation", "Un changement de tempo"], a: 1, fb: "La liquidation est l'érosion progressive du motif en fin de phrase. D'abord on en garde le rythme et la mélodie, puis juste le rythme, puis presque rien — la phrase se dissout dans la cadence. Procédé rhétorique très sophistiqué de 'conclusion' que Beethoven maîtrise parfaitement dans ses sonates." },
  { q: "La combinaison de plusieurs techniques de développement (ex. augmentation + substitution harmonique) :", opts: ["Est interdite en composition", "Produit des transformations plus riches et complexes — les familles se combinent librement", "N'est utilisée qu'au XXe siècle", "Efface complètement l'identité du motif"], a: 1, fb: "Les 4 familles de techniques se combinent librement. Un motif peut être simultanément transposé (famille C), avec une harmonie substituée (famille A) et joué pianissimo (famille B). Les combinaisons créent des transformations plus riches — c'est exactement ce que fait Beethoven dans les grands développements de ses sonates et symphonies." },
];

const questionsEn: Question[] = [
  { q: "What is a musical motive?", opts: ["A four-note chord", "The smallest distinct musical unit, immediately recognizable — the guiding thread of musical discourse", "A complete scale", "A dominant chord"], a: 1, fb: "A motive is the smallest autonomous and distinct musical cell. It contains a recognizable rhythmic and/or melodic identity that will be repeated and transformed to build coherent musical discourse. Beethoven builds his entire 5th Symphony from a 4-note motive." },
  { q: "What is the main role of a motive in a composition?", opts: ["To set the tempo", "To serve as a guiding thread — repeated and transformed, it gives coherence and direction to musical discourse", "To indicate the key", "To determine the number of measures"], a: 1, fb: "The motive is the guiding thread. Its repetition (strict or transformed) creates coherence: the listener recognizes the idea even when transformed, and follows the musical discourse. Without a leading motive, a succession of chords is 'groundless' — a list without direction." },
  { q: "What is the difference between 'support music' and 'discourse music'?", opts: ["Support music is faster", "Support music accompanies an external action; discourse music develops its own musical ideas autonomously", "Discourse music is shorter", "There is no difference"], a: 1, fb: "Support music (film, ballet, advertising) serves an external action — its structure can be fragmented according to the narrative. Discourse music (sonata, fugue, jazz standard) develops its own ideas logically, independently of any extra-musical context." },
  { q: "The 'paradox of repetition' in musical composition means that:", opts: ["You should never repeat", "Repetition is necessary for coherence, but dangerous if too pure — monotony threatens", "You should always repeat exactly", "Repetition is only rhythmic"], a: 1, fb: "Central paradox: without repetition, no coherence (the listener recognizes nothing); with too much identical repetition, monotony sets in. The solution: repeat while transforming. Variety within repetition is the very art of motivic development." },
  { q: "The three stages of a motive's life are:", opts: ["Introduction, development, coda", "Presentation → Repetition → Evolution", "Exposition, fugue, recapitulation", "Motive, theme, period"], a: 1, fb: "A motive follows three rhetorical stages: Presentation (establish the identity), Repetition (anchor the motive in the ear), Evolution (transform, develop, combine). This trajectory applies at the scale of the phrase (8 bars), the movement and the entire work." },
  { q: "How many constituent elements define a motive?", opts: ["2 (melody and rhythm)", "3 (melody, rhythm, harmony)", "5 (intervals, rhythm, harmony, accompaniment, dynamics)", "7 (one per note)"], a: 2, fb: "Five elements constitute a motive: (1) intervals (melodic contour), (2) rhythm (duration pattern), (3) harmony (supporting chords), (4) accompaniment (texture), (5) dynamics (nuances and articulation). Each element can be modified independently during development." },
  { q: "Among the 5 elements of a motive, which is often the most immediately recognizable?", opts: ["The melody (intervals)", "Rhythm — its pattern is often identifiable even if the pitches change", "The harmony", "The dynamics"], a: 1, fb: "Rhythm is often the most distinctive element. In Beethoven's ta-ta-ta-TAA motive (3 eighth notes + quarter note), it is recognizable even transposed to another key or played by a different instrument. Rhythm is the temporal DNA of the motive." },
  { q: "The 'accompaniment' element of a motive refers to:", opts: ["The main melody", "The texture surrounding the motive: arpeggios, block chords, independent bass line", "Dynamic nuances", "The tempo"], a: 1, fb: "Accompaniment is the musical texture surrounding the melodic motive. The same motive can sound radically different whether accompanied by arpeggios (lightness), block chords (solidity) or a contrapuntal bass line (polyphonic richness)." },
  { q: "The 'dynamics' element of a motive includes:", opts: ["Pitch heights only", "Nuances (forte/piano), articulation (legato/staccato) and attack — the physical expression of the motive", "The number of repetitions", "The key of the piece"], a: 1, fb: "Dynamics groups nuances (forte, piano, crescendo), articulation (legato, staccato, accent), and attack type. The same motive played pianissimo legato vs fortissimo staccato: two entirely different characters, without changing a single note." },
  { q: "Why are intervals a constituent element of the motive?", opts: ["Because they set the tempo", "Because characteristic melodic leaps (third, fifth, tritone) create the motive's distinctive melodic identity", "Because they indicate the meter", "Because they are always the same in all motives"], a: 1, fb: "Intervals are the melodic fingerprint of the motive. The minor third drop (G–Eb) in Beethoven's motive is immediately recognizable. A motive built on a tritone will sound tense; on a major third, bright. Intervals fix the melodic character." },
  { q: "Which motive does Beethoven use in his 5th Symphony (1808)?", opts: ["4 descending notes by semitones", "3 repeated notes + a minor third drop (G–G–G–Eb, ta-ta-ta-TAA)", "A C major arpeggio", "An ascending scale"], a: 1, fb: "G–G–G–Eb: 3 identically repeated notes + minor third drop. This motive is the seed of the entire 5th Symphony. Beethoven fragments it, transposes it, augments it across all 4 movements — an absolute demonstration of economy of means." },
  { q: "What is a 'leitmotiv' in Wagner?", opts: ["A particular tempo", "A recurring motive associated with a character or dramatic idea — transformed according to context", "A dominant chord", "An orchestral fugue"], a: 1, fb: "Wagner associates a musical motive (leitmotiv) with each character, concept or dramatic object in his operas. Siegfried's sword motive returns transformed according to the situation — glorious in triumph, dark in danger. This is motivic form extended to the scale of an entire opera." },
  { q: "How does John Williams inherit Wagner's technique in Star Wars?", opts: ["He uses the same harmonies", "He associates a leitmotiv with each character (Force theme, Imperial March) transforming it according to dramatic context", "He copies Wagner's rhythms", "He uses the same instruments"], a: 1, fb: "Williams directly inherits from Wagner: each character has their motive. The Force theme — calm and luminous — becomes the Imperial March for Darth Vader, with the same melodic contour but radically different harmonization (minor, brass, forte dynamics). Same technique, a century later." },
  { q: "What makes Beethoven's motive (5th Symphony) so effective is:", opts: ["Its length — more than 8 notes", "Its brevity and distinctiveness: only 4 notes, with an immediately memorable rhythm and interval", "Its harmonic complexity", "Its rare orchestration"], a: 1, fb: "The strength of the motive lies in its economy. 4 notes: 3 repeated (insistence) + 1 minor third drop (descending resolution). This simplicity makes it universally memorable and infinitely transformable. Beethoven draws 20 minutes of symphony from it — maximum economy, maximum expressiveness." },
  { q: "The leitmotiv technique is notably used by:", opts: ["Bach in his fugues", "Wagner and, later, John Williams in his film music", "Chopin in his nocturnes", "Debussy in his preludes"], a: 1, fb: "Wagner develops the leitmotiv in his operas (The Ring Cycle, Tristan und Isolde). This technique passes into cinema via Korngold, Herrmann and especially John Williams — who openly acknowledges his debt to Wagner in Star Wars." },
  { q: "Family A (harmony and accompaniment) is applied first because:", opts: ["It is easier", "It is the least radical transformation — the melodic and rhythmic identity of the motive remains intact", "It gives the best result", "It is the fastest to realize"], a: 1, fb: "By modifying the harmony or accompaniment texture, the 'color' of the motive is transformed without touching its melody-rhythm identity. The listener fully recognizes the motive — the change is subtle. This is why this family is applied first: remarkable effect, minimal risk of identity loss." },
  { q: "'Harmonic substitution' in motivic development consists of:", opts: ["Changing the melodic motive", "Replacing one chord with another of the same function or color (I → VI, V7 → SubV) under the same motive", "Changing the key of the piece", "Removing chords"], a: 1, fb: "Harmonic substitution changes the chords supporting the motive without touching the motive's notes. Replacing I with VI (diatonic substitution) gives a softer color; V7 with SubV (tritone substitution) produces a chromatic bass. The motive remains recognizable, the color changes completely." },
  { q: "Transforming the accompaniment into 'arpeggios' rather than 'block chords' modifies:", opts: ["The notes of the motive", "The texture — the way chords are deployed in time, creating lightness or movement", "The key", "The rhythm of the motive"], a: 1, fb: "Arpeggios break chords into successive notes — creating movement and lightness (Chopin). Block chords create solidity and impact (Beethoven). Same harmony, same melodic motive, completely different textures. Accompaniment transformation is one of the most frequent in composition." },
  { q: "'Counterpoint' as a motivic development technique consists of:", opts: ["Repeating the motive twice", "Adding an independent voice that responds, imitates or contrasts with the motive — enriching the polyphony", "Changing the tempo", "Inverting the intervals"], a: 1, fb: "Counterpoint adds one or more voices that dialogue with the main motive. This voice can imitate it (canon), respond in contrary motion, or accompany it in parallel sixths. The work becomes denser without modifying the motive — enrichment by addition, not transformation." },
  { q: "The 'bass line' as motivic development means:", opts: ["Playing the motive in the bass", "Transforming the bass into an independent melodic counterpoint — third, sixth or contrary motion — that dialogues with the motive", "Removing the bass", "Doubling the bass at the octave"], a: 1, fb: "Instead of simply doubling the harmonic bass, it is given its own melodic contour — a bass line in contrary motion to the motive, or in parallel thirds/sixths. This technique is very present in Bach (chorales) and Beethoven (sonatas): it enriches the texture without altering the motive." },
  { q: "Modifying the 'dynamics' of a motive (forte → piano) transforms:", opts: ["The pitch heights", "The intensity and expressive character — same melody, radically different emotional impact", "The rhythm", "The key"], a: 1, fb: "The same motive played fortissimo is menacing or triumphant; pianissimo, it becomes mysterious or tender. Beethoven systematically exploits this dichotomy: he presents his motive fortissimo, then repeats it pianissimo — double affirmation, double character. Dynamics transform the meaning without touching the notes." },
  { q: "Transposing a motive an octave upward produces:", opts: ["The same effect as the lower octave", "Luminosity, urgency and clarity — the high register is perceived as brighter and more intense", "A perceived slowdown", "A key change"], a: 1, fb: "The high register creates luminosity and tension (psychologically perceived as more urgent). The low octave creates depth, gravity, authority. Beethoven uses this register transformation systematically in his developments — same motive, different registers, contrasting dramatic effects." },
  { q: "Moving from legato to staccato on the same motive:", opts: ["Slows down the motive", "Changes the articulation — the character becomes incisive, light or nervous depending on context, without touching the pitches", "Modifies the intervals", "Changes the harmony"], a: 1, fb: "Legato = tied notes, continuous flow, lyrical or soft character. Staccato = detached notes, lively, light or incisive character. The same motive in legato seems nostalgic; in staccato, playful or urgent. Articulation is one of the finest and most expressive parameters of dynamic development." },
  { q: "Changing the 'timbre' in motivic development means:", opts: ["Changing the composer", "Entrusting the same motive to a different instrument (violins → brass, piano → orchestra) — same melody, radically different instrumental color", "Changing the key", "Modifying the rhythm"], a: 1, fb: "The same motive on violins seems lyrical; on brass, heroic; on flute, airy; on piano fortissimo, percussive. Timbre is the instrument's 'voice'. In symphonic developments, Beethoven passes the same motive through different orchestral families — pure timbre transformation, not notes." },
  { q: "The 'inversion' (inverted intervals) of a motive consists of:", opts: ["Playing the motive backwards", "Inverting each interval: an ascending third becomes a descending third (and vice versa)", "Repeating the motive twice as fast", "Transposing an octave"], a: 1, fb: "Inversion mirrors each interval. G–G–G–Eb (minor third drop) becomes G–G–G–Bb (minor third rise). The rhythmic contour remains identical; the melodic profile is inverted. Technique frequent in Bach's fugues and Beethoven's developments." },
  { q: "The 'retrograde' of a motive is:", opts: ["The motive played more slowly", "The motive played backwards — from the last note to the first", "The motive transposed an octave", "The motive repeated twice"], a: 1, fb: "Retrograde reverses the order of the notes: Eb–G–G–G is the retrograde of G–G–G–Eb (Beethoven). Technique used by Bach in canons, by Beethoven and by serialists. It may seem unrecognizable by ear but maintains logical coherence with the original material." },
  { q: "Adding 'passing notes' to a motive:", opts: ["Destroys the motive entirely", "Enriches the melodic contour by filling in the leaps — the original motive remains recognizable, the melody becomes more fluid", "Changes the rhythm", "Changes the key"], a: 1, fb: "Passing notes fill the intervals of the motive. A third leap (C–E) becomes a scale fragment (C–D–E). The rhythmic contour can remain identical. The motive is richer melodically, less 'angular', but its starting identity remains perceptible." },
  { q: "A 'non-rhythmic transformation' of a motive means:", opts: ["Keeping the rhythm identical but modifying the pitches according to the scale (harmonic sequence or transposition)", "Changing only the rhythm", "Removing all notes", "Inverting the motive"], a: 0, fb: "Non-rhythmic transformation preserves the motive's rhythmic pattern but slides the pitches along the scale (tonal sequence) or by exact transposition (real sequence). Rhythm — often the strongest identity — remains recognizable; the pitches vary. This is the harmonic sequence." },
  { q: "Why are inversion and retrograde 'Family C' transformations?", opts: ["Because they are the simplest", "Because they transform the melodic contour without necessarily touching the rhythm — pitches modified, temporal structure preserved", "Because they are applied after rhythmic alterations", "Because they only modify harmony"], a: 1, fb: "Inversion and retrograde modify pitches while often maintaining the rhythmic structure. They belong to melodic transformations (Family C). These are more radical than Family A (harmony) but less radical than Family D (rhythmic alterations)." },
  { q: "Omitting a note from a motive:", opts: ["Destroys the motive entirely", "Lightens the motive — the general contour can remain recognizable, creating a reduced or fragmented version", "Is never used in composition", "Must always be compensated by another note"], a: 1, fb: "Omitting a note creates a 'lighter' version of the motive — progressive liquidation technique (Schoenberg's term). The motive gradually loses its distinctive traits. Beethoven uses this in developments: the motive fragments until it dissolves into the final cadence." },
  { q: "'Augmentation' of a motive consists of:", opts: ["Playing the motive louder", "Doubling (or tripling) the duration of each note — the motive slows down, takes on a solemn breadth", "Transposing an octave", "Inverting the intervals"], a: 1, fb: "Augmentation doubles each duration: an eighth note becomes a quarter note, a quarter note becomes a half note. The motive stretches in time — effect of slow motion, solemnity, grandeur. Beethoven uses it in developments to create a sense of inevitability." },
  { q: "'Diminution' of a motive consists of:", opts: ["Playing the motive softer", "Dividing the duration of each note — the motive accelerates, becomes nervous or urgent", "Removing notes", "Inverting the motive"], a: 1, fb: "Diminution divides each duration: a quarter note becomes an eighth note, an eighth note becomes a sixteenth note. The motive accelerates — effect of rising tension, impatience, urgency. Technique frequent in fugue developments (Bach) and Beethoven's liquidation sections." },
  { q: "Changing the meter (3/4 → 4/4) transforms a motive by:", opts: ["Adding notes to it", "Changing its metric context — the same motive in a different meter creates a feeling of lightness, imbalance or new energy", "Modifying its pitches", "Doubling its duration"], a: 1, fb: "Transposing a motive from 4/4 to 3/4 gives it a waltz-like feel; from 3/4 to 2/4, a march-like energy. The barline shifts relative to the notes — accents fall in different places. Chopin uses this technique in his Scherzo No.2." },
  { q: "Why are rhythmic alterations applied last?", opts: ["Because they are harder to write", "Because rhythm is often the most distinctive element of the motive — modifying it is the most radical change, risking making the motive unrecognizable", "Because they require an orchestra", "Because they are the least expressive"], a: 1, fb: "Rhythm is often the most robust DNA of a motive — Beethoven's ta-ta-ta-TAA is recognizable even transposed to another key. Touching the rhythm risks losing the motive's identity. This is why rhythmic alterations come last: greatest transformative power — and greatest risk." },
  { q: "The 'rhythmic deregulation' of a motive consists of:", opts: ["Regularizing the syncopations", "Transforming strong beats into syncopations — displacing the motive's accents to create rhythmic tension or surprise", "Doubling the duration of notes", "Changing the tempo"], a: 1, fb: "Deregulation creates syncopations where the original motive had strong beats. The effect is rhythmic destabilization — the ear expected an accent in one place, it arrives displaced. Technique very present in jazz (off-beat phrasing) and Beethovenian developments." },
  { q: "The correct order of application of the 4 families is:", opts: ["D → C → B → A (rhythm first)", "A → B → C → D (harmony first, rhythm last)", "C → A → D → B (melodic first)", "There is no defined order"], a: 1, fb: "The order A–B–C–D goes from least to most radical: A (harmony/accompaniment) transforms the motive's identity least; D (rhythm) transforms it most. We start with transformations that leave the motive fully recognizable, progressing toward deeper transformations." },
  { q: "To apply a transformation that leaves the motive fully identifiable, one uses:", opts: ["Family D (rhythmic alterations)", "Family A (harmony and accompaniment) — the melodic contour and rhythm remain intact", "Family C (melodic transformations)", "Families B and D together"], a: 1, fb: "Family A is the least radical: changing the harmony or texture (arpeggios, counterpoint, substitution) leaves the motive entirely recognizable. The melody and rhythm — its two most identifiable traits — remain intact. It is the 'recoloring' of the motive, not its transformation." },
  { q: "How many families of motivic development techniques are there?", opts: ["3", "4", "5", "7"], a: 1, fb: "There are 4 families: A (harmony and accompaniment), B (dynamic arrangement), C (melodic transformations), D (rhythmic alterations). Each family groups techniques of similar radicality and is applied in this order — from least to most transformative." },
  { q: "In which year did Beethoven compose his 5th Symphony?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "Beethoven's 5th Symphony was completed in 1808 (dedicated to Prince Lobkowitz and Count Razumovsky). The same year the 6th Symphony (Pastoral) was released. Beethoven was in his 'heroic' period — also deaf for several years, which makes his motivic mastery all the more remarkable." },
  { q: "Beethoven is often associated with which aesthetic principle?", opts: ["Baroque ornamentation", "Economy of means — building the maximum from the minimum of motivic material", "Operatic melody", "Modal improvisation"], a: 1, fb: "Economy of means is the quintessential Beethovenian principle: extract the maximum from the minimum. 4 notes generate a symphony. This contrasted with the galant, ornamental style of his predecessors. For Beethoven, richness lies not in the quantity of material, but in the depth of its development." },
  { q: "To which compositional era does Beethoven belong?", opts: ["Baroque (1600–1750)", "Classicism (1750–1820) — with a foot in Romanticism", "Late Romanticism (1850–1900)", "Impressionism (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) is a turning point: his early works belong to Viennese Classicism (Haydn, Mozart), but his late works (Quartets op.132, Sonata op.111, 9th Symphony) anticipate Romanticism and even the 20th century. He transcends period categories." },
  { q: "Schoenberg notably analyzed Beethoven's technique in:", opts: ["The Art of Fugue", "Fundamentals of Musical Composition — a treatise formalizing Beethoven's phrase, motive, period and forms", "The Well-Tempered Clavier", "Berlioz's Treatise on Orchestration"], a: 1, fb: "Schoenberg wrote Fundamentals of Musical Composition at UCLA in the 1930s–40s (published posthumously in 1967). His treatise systematically analyzes Beethoven's phrase and motivic development — paradoxically, Schoenberg is also the father of twelve-tone technique, which abolishes Beethovenian tonality." },
  { q: "How does one recognize a good opening motive?", opts: ["It must be very long", "It is short, distinctive, memorable, and flexible enough to be transformed in multiple ways", "It must contain all the notes of the scale", "It must avoid dissonances"], a: 1, fb: "A good motive combines brevity (memorable), distinctiveness (recognizable among others) and flexibility (transformable). G–G–G–Eb satisfies all three criteria. A motive too complex is difficult to transform; too simple, it becomes monotonous. The balance is the composer's art." },
  { q: "What is the most common mistake with a motive in composition?", opts: ["Using it too often", "Repeating the motive identically too many times without transformation — monotony sets in quickly", "Transposing it to other keys", "Using it in different instrumental families"], a: 1, fb: "Pure repetition is the temptation and the trap. A motive repeated identically more than twice loses its power of attraction. The ear expects variety. The art is to maintain recognition (coherence) while renewing (variety) — the paradox of repetition." },
  { q: "What is the effect of a 'harmonic sequence' in motivic development?", opts: ["Removing the motive", "Repeating the motive at successive degrees of the scale — the effect is progressive tonal expansion", "Changing only the tempo", "Stopping the musical discourse"], a: 1, fb: "The harmonic sequence repeats the motive at each degree of the scale (I, II, III, IV...). The listener perceives both coherence (same motive) and movement (pitch change at each repetition). Effect of 'progression' or 'escalation' very effective in development." },
  { q: "In jazz improvisation, how does knowledge of motivic development improve playing?", opts: ["It allows playing more notes", "It gives tools to build a coherent discourse — expose an idea, repeat/transform it, develop it toward a climax, conclude", "It forces staying in the pentatonic scale", "It replaces knowledge of the harmonic grid"], a: 1, fb: "An improviser who masters motivic development builds a 'discourse' rather than a succession of notes. They expose a motive (a few notes), repeat and transform it (Family A, B, C or D), create a climax, then conclude. The listener follows the story. This is the difference between improvising 'within' the grid and improvising 'through' it." },
  { q: "'Liquidation' of a motive at the end of a phrase (Schoenberg) produces:", opts: ["A silence", "A progressive dissolution of the motive — it loses its distinctive traits one by one, signaling the approaching cadence", "A modulation", "A tempo change"], a: 1, fb: "Liquidation is the progressive erosion of the motive at the end of a phrase. First rhythm and melody are kept, then just the rhythm, then almost nothing — the phrase dissolves into the cadence. A very sophisticated rhetorical 'conclusion' device that Beethoven masters perfectly in his sonatas." },
  { q: "Combining several development techniques (e.g. augmentation + harmonic substitution):", opts: ["Is forbidden in composition", "Produces richer and more complex transformations — the families combine freely", "Is only used in the 20th century", "Completely erases the motive's identity"], a: 1, fb: "The 4 technique families combine freely. A motive can be simultaneously transposed (Family C), with substituted harmony (Family A) and played pianissimo (Family B). Combinations create richer transformations — exactly what Beethoven does in the great developments of his sonatas and symphonies." },
];

const questionsEs: Question[] = [
  { q: "¿Qué es un motivo musical?", opts: ["Un acorde de 4 sonidos", "La unidad musical más pequeña y distintiva, inmediatamente reconocible — hilo conductor del discurso musical", "Una escala completa", "Un acorde de dominante"], a: 1, fb: "El motivo es la célula musical autónoma y distintiva más pequeña. Contiene una identidad rítmica y/o melódica reconocible que se repetirá y transformará para construir un discurso musical coherente. Beethoven construye toda su 5ª Sinfonía a partir de un motivo de solo 4 notas." },
  { q: "¿Cuál es el papel principal del motivo en una composición?", opts: ["Fijar el tempo", "Servir de hilo conductor — repetido y transformado, da coherencia y dirección al discurso musical", "Indicar la tonalidad", "Determinar el número de compases"], a: 1, fb: "El motivo es el hilo conductor. Su repetición (estricta o transformada) crea coherencia: el oyente reconoce la idea aunque esté transformada, y así sigue el discurso musical. Sin motivo conductor, una sucesión de acordes está 'en el vacío' — una lista sin dirección." },
  { q: "¿Cuál es la diferencia entre 'música de apoyo' y 'música de discurso'?", opts: ["La música de apoyo es más rápida", "La música de apoyo acompaña una acción exterior; la música de discurso desarrolla sus propias ideas musicales de forma autónoma", "La música de discurso es más corta", "No hay ninguna diferencia"], a: 1, fb: "La música de apoyo (cine, ballet, publicidad) sirve a una acción exterior — su estructura puede fragmentarse según la narración. La música de discurso (sonata, fuga, estándar de jazz) desarrolla sus propias ideas lógicamente, independientemente de cualquier contexto extra-musical." },
  { q: "La 'paradoja de la repetición' en composición musical significa que:", opts: ["Nunca hay que repetir", "La repetición es necesaria para la coherencia, pero peligrosa si es demasiado pura — la monotonía amenaza", "Siempre hay que repetir exactamente", "La repetición es únicamente rítmica"], a: 1, fb: "Paradoja central: sin repetición, no hay coherencia (el oyente no reconoce nada); con demasiada repetición idéntica, se instala la monotonía. La solución: repetir transformando. La variedad dentro de la repetición es el arte mismo del desarrollo motívico." },
  { q: "Las tres etapas de la vida de un motivo son:", opts: ["Introducción, desarrollo, coda", "Presentación → Repetición → Evolución", "Exposición, fuga, reexposición", "Motivo, tema, período"], a: 1, fb: "Un motivo sigue tres etapas retóricas: Presentación (establecer la identidad), Repetición (anclar el motivo en el oído), Evolución (transformar, desarrollar, combinar). Esta trayectoria se aplica a escala de la frase (8 compases), del movimiento y de la obra entera." },
  { q: "¿Cuántos elementos constitutivos definen un motivo?", opts: ["2 (melodía y ritmo)", "3 (melodía, ritmo, armonía)", "5 (intervalos, ritmo, armonía, acompañamiento, dinámica)", "7 (uno por nota)"], a: 2, fb: "Cinco elementos constituyen un motivo: (1) intervalos (contorno melódico), (2) ritmo (esquema de duraciones), (3) armonía (acordes de apoyo), (4) acompañamiento (textura), (5) dinámica (matices y articulación). Cada elemento puede modificarse de forma independiente durante el desarrollo." },
  { q: "Entre los 5 elementos de un motivo, ¿cuál suele ser el más inmediatamente reconocible?", opts: ["La melodía (intervalos)", "El ritmo — su esquema es a menudo identificable aunque cambien las alturas", "La armonía", "La dinámica"], a: 1, fb: "El ritmo es a menudo el elemento más distintivo. En el motivo ta-ta-ta-TAA de Beethoven (3 corcheas + negra), se reconoce incluso transpuesto a otra tonalidad o tocado por un instrumento diferente. El ritmo es el ADN temporal del motivo." },
  { q: "El elemento 'acompañamiento' de un motivo designa:", opts: ["La melodía principal", "La textura que rodea al motivo: arpegios, acordes plaqués, línea de bajo independiente", "Los matices dinámicos", "El tempo"], a: 1, fb: "El acompañamiento es la textura musical que rodea al motivo melódico. El mismo motivo puede sonar radicalmente diferente según si va acompañado de arpegios (ligereza), acordes plaqués (solidez) o una línea de bajo en contrapunto (riqueza polifónica)." },
  { q: "El elemento 'dinámica' de un motivo incluye:", opts: ["Solo las alturas de las notas", "Los matices (forte/piano), la articulación (legato/staccato) y el ataque — la expresión física del motivo", "El número de repeticiones", "La tonalidad de la pieza"], a: 1, fb: "La dinámica agrupa los matices (forte, piano, crescendo), la articulación (legato, staccato, acento) y el tipo de ataque. El mismo motivo tocado pianissimo legato vs fortissimo staccato: dos caracteres completamente diferentes, sin cambiar una sola nota." },
  { q: "¿Por qué los intervalos son un elemento constitutivo del motivo?", opts: ["Porque fijan el tempo", "Porque los saltos melódicos característicos (tercera, quinta, tritono) crean la identidad melódica distintiva del motivo", "Porque indican el compás", "Porque son siempre los mismos en todos los motivos"], a: 1, fb: "Los intervalos son la huella melódica del motivo. La caída de tercera menor (Sol–Mib) en el motivo de Beethoven es inmediatamente reconocible. Un motivo construido sobre un tritono sonará tenso; sobre una tercera mayor, brillante. Los intervalos fijan el carácter melódico." },
  { q: "¿Qué motivo usa Beethoven en su 5ª Sinfonía (1808)?", opts: ["4 notas descendentes por semitonos", "3 notas repetidas + una caída de tercera menor (Sol–Sol–Sol–Mib, ta-ta-ta-TAA)", "Un arpegio de Do mayor", "Una escala ascendente"], a: 1, fb: "Sol–Sol–Sol–Mib: 3 notas repetidas idénticamente + caída de tercera menor. Este motivo es el germen de toda la 5ª Sinfonía. Beethoven lo fragmenta, lo transpone, lo aumenta en los 4 movimientos — demostración absoluta de la economía de medios." },
  { q: "¿Qué es un 'leitmotiv' en Wagner?", opts: ["Un tempo particular", "Un motivo recurrente asociado a un personaje o idea dramática — transformado según el contexto", "Un acorde de dominante", "Una fuga para orquesta"], a: 1, fb: "Wagner asocia en sus óperas un motivo musical (leitmotiv) a cada personaje, concepto u objeto dramático. El motivo de la espada de Sigfrido vuelve transformado según la situación — glorioso en el triunfo, oscuro en el peligro. Es la forma motívica extendida a la escala de toda una ópera." },
  { q: "¿Cómo hereda John Williams la técnica de Wagner en Star Wars?", opts: ["Usa las mismas armonías", "Asocia un leitmotiv a cada personaje (tema de la Fuerza, marcha imperial) transformándolo según el contexto dramático", "Copia los ritmos de Wagner", "Usa los mismos instrumentos"], a: 1, fb: "Williams hereda directamente de Wagner: cada personaje tiene su motivo. El tema de la Fuerza — tranquilo y luminoso — se convierte en la Marcha Imperial para Darth Vader, con el mismo contorno melódico pero una armonización radicalmente diferente (menor, metales, dinámica forte). Misma técnica, un siglo después." },
  { q: "Lo que hace tan eficaz al motivo de Beethoven (5ª Sinfonía) es:", opts: ["Su longitud — más de 8 notas", "Su brevedad y distintividad: solo 4 notas, con un ritmo e intervalo inmediatamente memorables", "Su complejidad armónica", "Su rara orquestación"], a: 1, fb: "La fuerza del motivo está en su economía. 4 notas: 3 repetidas (insistencia) + 1 caída de tercera menor (resolución descendente). Esta sencillez lo hace universalmente memorable e infinitamente transformable. Beethoven extrae 20 minutos de sinfonía de él — economía máxima, expresividad máxima." },
  { q: "La técnica del leitmotiv es utilizada notablemente por:", opts: ["Bach en sus fugas", "Wagner y, más tarde, John Williams en sus músicas de cine", "Chopin en sus nocturnos", "Debussy en sus preludios"], a: 1, fb: "Wagner desarrolla el leitmotiv en sus óperas (El anillo del Nibelungo, Tristán e Isolda). Esta técnica pasa al cine a través de Korngold, Herrmann y sobre todo John Williams — quien reconoce abiertamente su deuda con Wagner en Star Wars." },
  { q: "La familia A (armonía y acompañamiento) se aplica primero porque:", opts: ["Es más fácil", "Es la transformación menos radical — la identidad melódica y rítmica del motivo permanece intacta", "Da el mejor resultado", "Es la más rápida de realizar"], a: 1, fb: "Al modificar la armonía o la textura del acompañamiento, se transforma el 'color' del motivo sin tocar su identidad melodía-ritmo. El oyente reconoce plenamente el motivo — el cambio es sutil. Por eso esta familia se aplica primero: efecto notable, riesgo mínimo de pérdida de identidad." },
  { q: "La 'sustitución armónica' en el desarrollo motívico consiste en:", opts: ["Cambiar el motivo melódico", "Reemplazar un acorde por otro de la misma función o color (I → VI, V7 → SubV) bajo el mismo motivo", "Cambiar la tonalidad de la pieza", "Suprimir acordes"], a: 1, fb: "La sustitución armónica cambia los acordes que sostienen el motivo sin tocar las notas del motivo en sí. Reemplazar I por VI (sustitución diatónica) da un color más suave; V7 por SubV (sustitución tritónica) produce un bajo cromático. El motivo sigue siendo reconocible, el color cambia totalmente." },
  { q: "Transformar el acompañamiento en 'arpegios' en lugar de 'acordes plaqués' modifica:", opts: ["Las notas del motivo", "La textura — la forma en que los acordes se despliegan en el tiempo, creando ligereza o movimiento", "La tonalidad", "El ritmo del motivo"], a: 1, fb: "Los arpegios descomponen los acordes en notas sucesivas — creando movimiento y ligereza (Chopin). Los acordes plaqués crean solidez e impacto (Beethoven). Misma armonía, mismo motivo melódico, texturas completamente diferentes." },
  { q: "El 'contrapunto' como técnica de desarrollo motívico consiste en:", opts: ["Repetir el motivo dos veces", "Añadir una voz independiente que responde, imita o contrasta con el motivo — enriqueciendo la polifonía", "Cambiar el tempo", "Invertir los intervalos"], a: 1, fb: "El contrapunto añade una o varias voces que dialogan con el motivo principal. Esta voz puede imitarlo (canon), responderle en movimiento contrario, o acompañarlo en sextas paralelas. La obra se vuelve más densa sin modificar el motivo — enriquecimiento por adición, no por transformación." },
  { q: "La 'línea de bajo' como desarrollo motívico significa:", opts: ["Tocar el motivo en el bajo", "Transformar el bajo en contrapunto melódico independiente — tercera, sexta o movimiento contrario — que dialoga con el motivo", "Suprimir el bajo", "Doblar el bajo a la octava"], a: 1, fb: "En lugar de simplemente doblar el bajo armónico, se le da un contorno melódico propio — una línea de bajo en movimiento contrario al motivo, o en terceras/sextas paralelas. Técnica muy presente en Bach (corales) y Beethoven (sonatas): enriquece la textura sin alterar el motivo." },
  { q: "Modificar los 'matices' de un motivo (forte → piano) transforma:", opts: ["Las alturas de las notas", "La intensidad y el carácter expresivo — misma melodía, impacto emocional radicalmente diferente", "El ritmo", "La tonalidad"], a: 1, fb: "El mismo motivo tocado fortissimo es amenazador o triunfal; pianissimo, se vuelve misterioso o tierno. Beethoven explota sistemáticamente esta dicotomía: presenta su motivo fortissimo, luego lo repite pianissimo — doble afirmación, doble carácter. Los matices transforman el sentido sin tocar las notas." },
  { q: "Transponer un motivo una octava hacia arriba produce:", opts: ["El mismo efecto que en la octava inferior", "Luminosidad, urgencia y claridad — el registro agudo se percibe como más brillante e intenso", "Una ralentización percibida", "Un cambio de tonalidad"], a: 1, fb: "El registro agudo crea luminosidad y tensión (percibida como más urgente psicológicamente). La octava grave crea profundidad, gravedad, autoridad. Beethoven usa esta transformación de registro sistemáticamente en sus desarrollos — mismo motivo, registros diferentes, efectos dramáticos contrastantes." },
  { q: "Pasar de legato a staccato en el mismo motivo:", opts: ["Ralentiza el motivo", "Cambia la articulación — el carácter se vuelve incisivo, ligero o nervioso según el contexto, sin tocar las alturas", "Modifica los intervalos", "Cambia la armonía"], a: 1, fb: "Legato = notas ligadas, flujo continuo, carácter lírico o suave. Staccato = notas separadas, carácter vivo, ligero o incisivo. El mismo motivo en legato parece nostálgico; en staccato, juguetón o urgente. La articulación es uno de los parámetros más finos y expresivos del desarrollo dinámico." },
  { q: "Cambiar el 'timbre' en un desarrollo motívico significa:", opts: ["Cambiar el compositor", "Confiar el mismo motivo a un instrumento diferente (violines → metales, piano → orquesta) — misma melodía, color instrumental radicalmente diferente", "Cambiar la tonalidad", "Modificar el ritmo"], a: 1, fb: "El mismo motivo en violines parece lírico; en metales, heroico; en flauta, aéreo; en piano fortissimo, percutivo. El timbre es la 'voz' del instrumento. En los desarrollos sinfónicos, Beethoven pasa el mismo motivo por diferentes familias orquestales — transformación pura de timbre, no de notas." },
  { q: "La 'inversión' (inversión de los intervalos) de un motivo consiste en:", opts: ["Tocar el motivo al revés", "Invertir cada intervalo: una subida de tercera se convierte en una bajada de tercera (y viceversa)", "Repetir el motivo dos veces más rápido", "Transponer una octava"], a: 1, fb: "La inversión espeja cada intervalo. Sol–Sol–Sol–Mib (caída de tercera menor) se convierte en Sol–Sol–Sol–Sib (subida de tercera menor). El contorno rítmico permanece idéntico; el perfil melódico se invierte. Técnica frecuente en las fugas de Bach y los desarrollos de Beethoven." },
  { q: "El 'retrógrado' de un motivo es:", opts: ["El motivo tocado más lentamente", "El motivo tocado al revés — desde la última nota hasta la primera", "El motivo transpuesto a la octava", "El motivo repetido dos veces"], a: 1, fb: "El retrógrado invierte el orden de las notas: Mib–Sol–Sol–Sol es el retrógrado de Sol–Sol–Sol–Mib (Beethoven). Técnica usada por Bach en sus cánones, por Beethoven y por los serialistas. Puede parecer irreconocible al oído pero mantiene coherencia lógica con el material original." },
  { q: "Añadir 'notas de paso' a un motivo:", opts: ["Destruye el motivo por completo", "Enriquece el contorno melódico llenando los saltos — el motivo original sigue siendo reconocible, la melodía se vuelve más fluida", "Cambia el ritmo", "Cambia la tonalidad"], a: 1, fb: "Las notas de paso rellenan los intervalos del motivo. Un salto de tercera (Do–Mi) se convierte en un fragmento de escala (Do–Re–Mi). El contorno rítmico puede permanecer idéntico. El motivo es más rico melódicamente, menos 'angular', pero su identidad de partida sigue siendo perceptible." },
  { q: "Una 'transformación no rítmica' de un motivo significa:", opts: ["Conservar el ritmo idéntico pero modificar las alturas según la escala (marcha armónica o transposición)", "Cambiar únicamente el ritmo", "Suprimir todas las notas", "Invertir el motivo"], a: 0, fb: "La transformación no rítmica conserva el esquema rítmico del motivo pero desplaza las alturas según la escala (secuencia tonal) o por transposición exacta (secuencia real). El ritmo — a menudo la identidad más fuerte — sigue siendo reconocible; las alturas varían. Esta es la marcha armónica o secuencia." },
  { q: "¿Por qué la inversión y el retrógrado son transformaciones de la 'familia C'?", opts: ["Porque son las más sencillas", "Porque transforman el contorno melódico sin tocar necesariamente el ritmo — alturas modificadas, estructura temporal preservada", "Porque se aplican después de las alteraciones rítmicas", "Porque solo modifican la armonía"], a: 1, fb: "La inversión y el retrógrado modifican las alturas manteniendo a menudo la estructura rítmica. Pertenecen a las transformaciones melódicas (familia C). Son más radicales que la familia A (armonía) pero menos que la familia D (alteraciones rítmicas)." },
  { q: "La omisión de una nota de un motivo:", opts: ["Destruye el motivo por completo", "Aligera el motivo — el contorno general puede seguir siendo reconocible, creando una versión reducida o fragmentada", "Nunca se usa en composición", "Siempre debe compensarse con otra nota"], a: 1, fb: "Omitir una nota crea una versión 'aligerada' del motivo — técnica de liquidación progresiva (término de Schoenberg). El motivo pierde progresivamente sus rasgos distintivos. Beethoven usa esta técnica al final de los desarrollos: el motivo se fragmenta hasta disolverse en la cadencia final." },
  { q: "La 'aumentación' de un motivo consiste en:", opts: ["Tocar el motivo más fuerte", "Duplicar (o triplicar) la duración de cada nota — el motivo se ralentiza, adquiere una amplitud solemne", "Transponer una octava", "Invertir los intervalos"], a: 1, fb: "La aumentación duplica cada duración: una corchea se convierte en negra, una negra en blanca. El motivo se extiende en el tiempo — efecto de cámara lenta, solemnidad, grandiosidad. Beethoven la usa en los desarrollos para crear un sentimiento de inevitabilidad." },
  { q: "La 'disminución' de un motivo consiste en:", opts: ["Tocar el motivo más suave", "Dividir la duración de cada nota — el motivo se acelera, se vuelve nervioso o urgente", "Suprimir notas", "Invertir el motivo"], a: 1, fb: "La disminución divide cada duración: una negra se convierte en corchea, una corchea en semicorchea. El motivo se acelera — efecto de tensión creciente, impaciencia, urgencia. Técnica frecuente en los desarrollos de fugas (Bach) y las secciones de liquidación de Beethoven." },
  { q: "El cambio de compás (3/4 → 4/4) transforma un motivo:", opts: ["Añadiéndole notas", "Cambiando su contexto métrico — el mismo motivo en un compás diferente crea un sentimiento de ligereza, desequilibrio o nueva energía", "Modificando sus alturas", "Duplicando su duración"], a: 1, fb: "Transponer un motivo de 4/4 a 3/4 le da un aire de vals; de 3/4 a 2/4, una energía de marcha. La barra de compás se desplaza respecto a las notas — los acentos caen en otros lugares. Chopin usa esta técnica en su Scherzo nº2." },
  { q: "¿Por qué las alteraciones rítmicas se aplican al final?", opts: ["Porque son más difíciles de escribir", "Porque el ritmo es a menudo el elemento más distintivo del motivo — modificarlo es el cambio más radical, con riesgo de volverlo irreconocible", "Porque requieren una orquesta", "Porque son las menos expresivas"], a: 1, fb: "El ritmo es a menudo el ADN más robusto de un motivo — el ta-ta-ta-TAA de Beethoven es reconocible incluso transpuesto a otra tonalidad. Tocar el ritmo implica el riesgo de perder la identidad del motivo. Por eso las alteraciones rítmicas van al final: mayor poder transformador — y mayor riesgo." },
  { q: "La 'desregulación' rítmica de un motivo consiste en:", opts: ["Regularizar las síncopas", "Transformar los tiempos fuertes en síncopas — desplazar los acentos del motivo para crear tensión o sorpresa rítmica", "Duplicar la duración de las notas", "Cambiar el tempo"], a: 1, fb: "La desregulación crea síncopas donde el motivo original tenía tiempos fuertes. El efecto es de desestabilización rítmica — el oído esperaba un acento en un lugar, llega desplazado. Técnica muy presente en el jazz (fraseo off-beat) y en los desarrollos beethovenianos." },
  { q: "El orden correcto de aplicación de las 4 familias es:", opts: ["D → C → B → A (ritmo primero)", "A → B → C → D (armonía primero, ritmo al final)", "C → A → D → B (melódico primero)", "No hay un orden definido"], a: 1, fb: "El orden A–B–C–D va de menos a más radical: A (armonía/acompañamiento) transforma menos la identidad del motivo; D (ritmo) la transforma más. Se comienza por las transformaciones que dejan el motivo plenamente reconocible, para avanzar progresivamente hacia transformaciones más profundas." },
  { q: "Para aplicar una transformación que deje el motivo plenamente identificable, se usa:", opts: ["La familia D (alteraciones rítmicas)", "La familia A (armonía y acompañamiento) — el contorno melódico y el ritmo permanecen intactos", "La familia C (transformaciones melódicas)", "Las familias B y D juntas"], a: 1, fb: "La familia A es la menos radical: cambiar la armonía o la textura (arpegios, contrapunto, sustitución) deja el motivo completamente reconocible. La melodía y el ritmo — sus dos rasgos más identificables — permanecen intactos. Es el 'recoloreado' del motivo, no su transformación." },
  { q: "¿Cuántas familias de técnicas de desarrollo motívico existen?", opts: ["3", "4", "5", "7"], a: 1, fb: "Existen 4 familias: A (armonía y acompañamiento), B (disposición dinámica), C (transformaciones melódicas), D (alteraciones rítmicas). Cada familia agrupa técnicas de un grado de radicalidad similar y se aplica en este orden — de menos a más transformador." },
  { q: "¿En qué año compuso Beethoven su 5ª Sinfonía?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "La 5ª Sinfonía de Beethoven se completó en 1808 (dedicada al príncipe Lobkowitz y al conde Razumovsky). El mismo año salió la 6ª Sinfonía (Pastoral). Beethoven estaba entonces en pleno período 'heroico' — también sordo desde hacía varios años, lo que hace aún más notable su dominio motívico." },
  { q: "Beethoven está frecuentemente asociado a qué principio estético:", opts: ["La ornamentación barroca", "La economía de medios — construir el máximo a partir del mínimo de material motívico", "La melodía operística", "La improvisación modal"], a: 1, fb: "La economía de medios es el principio beethoveniano por excelencia: extraer el máximo del mínimo. 4 notas generan una sinfonía. Este enfoque contrastaba con el estilo galante y ornamental de sus predecesores. Para Beethoven, la riqueza no está en la cantidad de material, sino en la profundidad de su desarrollo." },
  { q: "¿A qué época compositiva pertenece Beethoven?", opts: ["Barroco (1600–1750)", "Clasicismo (1750–1820) — con un pie en el Romanticismo", "Romanticismo tardío (1850–1900)", "Impresionismo (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) es una bisagra: sus primeras obras se inscriben en el clasicismo vienés (Haydn, Mozart), pero sus obras tardías (Cuartetos op.132, Sonata op.111, 9ª Sinfonía) anticipan el Romanticismo e incluso el siglo XX. Trasciende las categorías de época." },
  { q: "Schoenberg analizó notablemente la técnica de Beethoven en:", opts: ["El arte de la fuga", "Fundamentals of Musical Composition — tratado que formaliza la frase, el motivo, el período y las formas beethovenianas", "El clave bien temperado", "El Tratado de orquestación de Berlioz"], a: 1, fb: "Schoenberg redactó Fundamentals of Musical Composition en la UCLA en los años 1930–40 (publicado póstumamente en 1967). Su tratado analiza sistemáticamente la frase y el desarrollo motívico de Beethoven — paradójicamente, Schoenberg es también el padre del dodecafonismo, que abolió la tonalidad beethoveniana." },
  { q: "¿Cómo se reconoce un buen motivo inicial?", opts: ["Debe ser muy largo", "Es corto, distintivo, memorable, y suficientemente flexible para ser transformado de múltiples formas", "Debe contener todas las notas de la escala", "Debe evitar las disonancias"], a: 1, fb: "Un buen motivo combina brevedad (memorable), distintividad (reconocible entre otros) y flexibilidad (transformable). Sol–Sol–Sol–Mib satisface los tres criterios. Un motivo demasiado complejo es difícil de transformar; demasiado simple, se vuelve monótono. El equilibrio es el arte del compositor." },
  { q: "¿Cuál es el error más común con un motivo en composición?", opts: ["Usarlo demasiado", "Repetir el motivo idénticamente demasiadas veces seguidas sin transformación — la monotonía se instala rápidamente", "Transponerlo a otras tonalidades", "Usarlo en diferentes familias instrumentales"], a: 1, fb: "La repetición pura es la tentación y la trampa. Un motivo repetido idénticamente más de dos veces pierde su poder de atracción. El oído espera variedad. El arte consiste en mantener el reconocimiento (coherencia) mientras se renueva (variedad) — esta es la paradoja de la repetición." },
  { q: "¿Cuál es el efecto de una 'marcha armónica' en el desarrollo de un motivo?", opts: ["Suprimir el motivo", "Repetir el motivo en grados sucesivos de la escala — el efecto es de expansión tonal progresiva", "Cambiar solo el tempo", "Detener el discurso musical"], a: 1, fb: "La marcha armónica repite el motivo en cada grado de la escala (I, II, III, IV...). El oyente percibe a la vez la coherencia (mismo motivo) y el movimiento (cambio de altura en cada repetición). Efecto de 'progresión' o 'escalada' muy efectivo en el desarrollo." },
  { q: "En la improvisación de jazz, ¿cómo mejora el juego el conocimiento del desarrollo motívico?", opts: ["Permite tocar más notas", "Proporciona herramientas para construir un discurso coherente — exponer una idea, repetirla/transformarla, desarrollarla hacia un clímax, concluir", "Obliga a quedarse en la escala pentatónica", "Reemplaza el conocimiento de la progresión armónica"], a: 1, fb: "Un improvisador que domina el desarrollo motívico construye un 'discurso' más que una sucesión de notas. Expone un motivo (algunas notas), lo repite y lo transforma (familia A, B, C o D), crea un clímax, luego concluye. El oyente sigue la historia. Esta es la diferencia entre improvisar 'dentro' de la progresión e improvisar 'a través' de ella." },
  { q: "La 'liquidación' de un motivo al final de una frase (Schoenberg) produce:", opts: ["Un silencio", "Una disolución progresiva del motivo — pierde sus rasgos distintivos uno a uno, señalando que la cadencia se aproxima", "Una modulación", "Un cambio de tempo"], a: 1, fb: "La liquidación es la erosión progresiva del motivo al final de una frase. Primero se conservan el ritmo y la melodía, luego solo el ritmo, luego casi nada — la frase se disuelve en la cadencia. Procedimiento retórico muy sofisticado de 'conclusión' que Beethoven domina perfectamente en sus sonatas." },
  { q: "La combinación de varias técnicas de desarrollo (ej. aumentación + sustitución armónica):", opts: ["Está prohibida en composición", "Produce transformaciones más ricas y complejas — las familias se combinan libremente", "Solo se usa en el siglo XX", "Borra completamente la identidad del motivo"], a: 1, fb: "Las 4 familias de técnicas se combinan libremente. Un motivo puede ser simultáneamente transpuesto (familia C), con armonía sustituida (familia A) y tocado pianissimo (familia B). Las combinaciones crean transformaciones más ricas — exactamente lo que hace Beethoven en los grandes desarrollos de sus sonatas y sinfonías." },
];

const questionsDe: Question[] = [
  { q: "Was ist ein musikalisches Motiv?", opts: ["Ein Vierklang-Akkord", "Die kleinste eigenständige und erkennbare musikalische Einheit — der rote Faden des musikalischen Diskurses", "Eine vollständige Tonleiter", "Ein Dominantakkord"], a: 1, fb: "Ein Motiv ist die kleinste autonome und eigenständige musikalische Zelle. Es enthält eine wiedererkennbare rhythmische und/oder melodische Identität, die wiederholt und transformiert wird, um einen kohärenten musikalischen Diskurs aufzubauen. Beethoven baut seine gesamte 5. Sinfonie aus einem 4-Noten-Motiv." },
  { q: "Was ist die Hauptaufgabe des Motivs in einer Komposition?", opts: ["Das Tempo festlegen", "Als roter Faden dienen — wiederholt und transformiert, gibt es dem musikalischen Diskurs Kohärenz und Richtung", "Die Tonart anzeigen", "Die Anzahl der Takte bestimmen"], a: 1, fb: "Das Motiv ist der rote Faden. Seine Wiederholung (streng oder transformiert) schafft Kohärenz: der Hörer erkennt die Idee auch transformiert und folgt dem musikalischen Diskurs. Ohne leitendes Motiv ist eine Abfolge von Akkorden 'bodenlos' — eine Liste ohne Richtung." },
  { q: "Was ist der Unterschied zwischen 'Unterstützungsmusik' und 'Diskursmusik'?", opts: ["Unterstützungsmusik ist schneller", "Unterstützungsmusik begleitet eine äußere Handlung; Diskursmusik entwickelt ihre eigenen musikalischen Ideen autonom", "Diskursmusik ist kürzer", "Es gibt keinen Unterschied"], a: 1, fb: "Unterstützungsmusik (Film, Ballett, Werbung) dient einer äußeren Handlung — ihre Struktur kann entsprechend der Erzählung fragmentiert sein. Diskursmusik (Sonate, Fuge, Jazzstandard) entwickelt ihre eigenen Ideen logisch, unabhängig von jedem außermusikalischen Kontext." },
  { q: "Das 'Paradox der Wiederholung' in der musikalischen Komposition bedeutet, dass:", opts: ["Man niemals wiederholen sollte", "Wiederholung für die Kohärenz notwendig ist, aber gefährlich wenn zu rein — Monotonie droht", "Man immer exakt wiederholen sollte", "Wiederholung nur rhythmisch ist"], a: 1, fb: "Zentrales Paradox: ohne Wiederholung keine Kohärenz (der Hörer erkennt nichts); zu viel identische Wiederholung führt zu Monotonie. Die Lösung: wiederholend transformieren. Vielfalt in der Wiederholung ist die eigentliche Kunst der motivischen Entwicklung." },
  { q: "Die drei Phasen des Lebens eines Motivs sind:", opts: ["Einleitung, Durchführung, Coda", "Vorstellung → Wiederholung → Entwicklung", "Exposition, Fuge, Reprise", "Motiv, Thema, Periode"], a: 1, fb: "Ein Motiv durchläuft drei rhetorische Phasen: Vorstellung (Identität etablieren), Wiederholung (Motiv im Ohr verankern), Entwicklung (transformieren, entfalten, kombinieren). Diese Verlaufskurve gilt auf der Ebene der Phrase (8 Takte), des Satzes und des gesamten Werkes." },
  { q: "Wie viele konstitutive Elemente definieren ein Motiv?", opts: ["2 (Melodie und Rhythmus)", "3 (Melodie, Rhythmus, Harmonie)", "5 (Intervalle, Rhythmus, Harmonie, Begleitung, Dynamik)", "7 (eines pro Note)"], a: 2, fb: "Fünf Elemente konstituieren ein Motiv: (1) Intervalle (melodische Kontur), (2) Rhythmus (Dauernmuster), (3) Harmonie (stützende Akkorde), (4) Begleitung (Textur), (5) Dynamik (Nuancen und Artikulation). Jedes Element kann bei der Entwicklung unabhängig verändert werden." },
  { q: "Welches der 5 Elemente eines Motivs ist oft am unmittelbarsten erkennbar?", opts: ["Die Melodie (Intervalle)", "Der Rhythmus — sein Muster ist oft erkennbar, auch wenn die Tonhöhen sich ändern", "Die Harmonie", "Die Dynamik"], a: 1, fb: "Der Rhythmus ist oft das markanteste Element. Im ta-ta-ta-TAA-Motiv Beethovens (3 Achtel + Viertel) ist es wiedererkennbar, auch wenn es in eine andere Tonart transponiert oder von einem anderen Instrument gespielt wird. Der Rhythmus ist die zeitliche DNA des Motivs." },
  { q: "Das Element 'Begleitung' eines Motivs bezeichnet:", opts: ["Die Hauptmelodie", "Die Textur, die das Motiv umgibt: Arpeggien, Block-Akkorde, selbstständige Basslinie", "Dynamische Nuancen", "Das Tempo"], a: 1, fb: "Die Begleitung ist die musikalische Textur, die das melodische Motiv umgibt. Dasselbe Motiv kann je nach Begleitung (Arpeggien für Leichtigkeit, Block-Akkorde für Solidität, kontrapunktische Basslinie für polyfone Fülle) radikal unterschiedlich klingen." },
  { q: "Das Element 'Dynamik' eines Motivs umfasst:", opts: ["Nur die Tonhöhen", "Nuancen (forte/piano), Artikulation (legato/staccato) und Anschlag — der physische Ausdruck des Motivs", "Die Anzahl der Wiederholungen", "Die Tonart des Stücks"], a: 1, fb: "Dynamik umfasst Nuancen (forte, piano, crescendo), Artikulation (legato, staccato, Akzent) und Anschlagsart. Dasselbe Motiv pianissimo legato vs fortissimo staccato gespielt: zwei völlig unterschiedliche Charaktere, ohne eine einzige Note zu ändern." },
  { q: "Warum sind Intervalle ein konstitutives Element des Motivs?", opts: ["Weil sie das Tempo bestimmen", "Weil charakteristische melodische Sprünge (Terz, Quinte, Tritonus) die unverwechselbare melodische Identität des Motivs schaffen", "Weil sie das Metrum anzeigen", "Weil sie in allen Motiven immer gleich sind"], a: 1, fb: "Intervalle sind der melodische Fingerabdruck des Motivs. Der Kleinterz-Fall (G–Es) in Beethovens Motiv ist sofort erkennbar. Ein Motiv auf einem Tritonus klingt angespannt; auf einer großen Terz, strahlend. Intervalle bestimmen den melodischen Charakter." },
  { q: "Welches Motiv verwendet Beethoven in seiner 5. Sinfonie (1808)?", opts: ["4 absteigende Noten in Halbtonschritten", "3 wiederholte Noten + ein Kleinterz-Fall (G–G–G–Es, ta-ta-ta-TAA)", "Ein C-Dur-Arpeggio", "Eine aufsteigende Tonleiter"], a: 1, fb: "G–G–G–Es: 3 identisch wiederholte Noten + Kleinterz-Fall. Dieses Motiv ist der Keim der gesamten 5. Sinfonie. Beethoven fragmentiert es, transponiert es, vergrößert es in allen 4 Sätzen — absolute Demonstration der Ökonomie der Mittel." },
  { q: "Was ist ein 'Leitmotiv' bei Wagner?", opts: ["Ein bestimmtes Tempo", "Ein wiederkehrendes Motiv, das mit einer Figur oder dramatischen Idee verbunden ist — je nach Kontext transformiert", "Ein Dominantakkord", "Eine Orchesterfuge"], a: 1, fb: "Wagner verbindet in seinen Opern ein musikalisches Motiv (Leitmotiv) mit jeder Figur, jedem Konzept oder dramatischen Objekt. Siegfrieds Schwert-Motiv kehrt je nach Situation transformiert zurück — glorreich im Triumph, dunkel in der Gefahr. Dies ist motivische Form im Maßstab einer gesamten Oper." },
  { q: "Wie erbt John Williams Wagners Technik in Star Wars?", opts: ["Er verwendet dieselben Harmonien", "Er verbindet ein Leitmotiv mit jeder Figur (Force-Thema, Imperialer Marsch) und transformiert es je nach dramatischem Kontext", "Er kopiert Wagners Rhythmen", "Er verwendet dieselben Instrumente"], a: 1, fb: "Williams erbt direkt von Wagner: jede Figur hat ihr Motiv. Das Force-Thema — ruhig und licht — wird zum Imperialen Marsch für Darth Vader, mit derselben melodischen Kontur, aber radikal unterschiedlicher Harmonisierung (Moll, Blechbläser, forte-Dynamik). Dieselbe Technik, ein Jahrhundert später." },
  { q: "Was macht Beethovens Motiv (5. Sinfonie) so wirkungsvoll:", opts: ["Seine Länge — mehr als 8 Noten", "Seine Kürze und Unverwechselbarkeit: nur 4 Noten, mit einem sofort einprägsamen Rhythmus und Intervall", "Seine harmonische Komplexität", "Seine seltene Orchestrierung"], a: 1, fb: "Die Stärke des Motivs liegt in seiner Ökonomie. 4 Noten: 3 wiederholte (Insistenz) + 1 Kleinterz-Fall (absteigende Auflösung). Diese Einfachheit macht es universell einprägsam und unendlich transformierbar. Beethoven schöpft daraus 20 Minuten Sinfonie — maximale Ökonomie, maximale Ausdruckskraft." },
  { q: "Die Leitmotiv-Technik wird insbesondere verwendet von:", opts: ["Bach in seinen Fugen", "Wagner und später John Williams in seiner Filmmusik", "Chopin in seinen Nocturnes", "Debussy in seinen Préludes"], a: 1, fb: "Wagner entwickelt das Leitmotiv in seinen Opern (Der Ring des Nibelungen, Tristan und Isolde). Diese Technik gelangt über Korngold, Herrmann und vor allem John Williams ins Kino — der seine Schuld gegenüber Wagner in Star Wars offen anerkennt." },
  { q: "Familie A (Harmonie und Begleitung) wird zuerst angewendet, weil:", opts: ["Sie einfacher ist", "Sie die am wenigsten radikale Transformation ist — die melodische und rhythmische Identität des Motivs bleibt intakt", "Sie das beste Ergebnis liefert", "Sie am schnellsten zu realisieren ist"], a: 1, fb: "Durch die Veränderung der Harmonie oder Begleitungstextur wird die 'Farbe' des Motivs transformiert, ohne seine Melodie-Rhythmus-Identität anzutasten. Der Hörer erkennt das Motiv vollständig — die Änderung ist subtil. Daher wird diese Familie zuerst angewendet: bemerkenswerte Wirkung, minimales Risiko des Identitätsverlusts." },
  { q: "'Harmonische Substitution' in der motivischen Entwicklung besteht aus:", opts: ["Dem Verändern des melodischen Motivs", "Dem Ersetzen eines Akkords durch einen anderen gleicher Funktion oder Farbe (I → VI, V7 → SubV) unter demselben Motiv", "Dem Ändern der Tonart des Stücks", "Dem Entfernen von Akkorden"], a: 1, fb: "Harmonische Substitution ändert die stützenden Akkorde, ohne die Motivnoten anzutasten. I durch VI zu ersetzen (diatonische Substitution) gibt eine weichere Farbe; V7 durch SubV (Tritonus-Substitution) erzeugt einen chromatischen Bass. Das Motiv bleibt erkennbar, die Farbe ändert sich vollständig." },
  { q: "Die Begleitung von 'Arpeggien' statt 'Block-Akkorden' zu verändern, modifiziert:", opts: ["Die Noten des Motivs", "Die Textur — die Art, wie Akkorde im Laufe der Zeit entfaltet werden, Leichtigkeit oder Bewegung erzeugend", "Die Tonart", "Den Rhythmus des Motivs"], a: 1, fb: "Arpeggien zerlegen Akkorde in sukzessive Noten — dadurch entstehen Bewegung und Leichtigkeit (Chopin). Block-Akkorde schaffen Solidität und Wirkung (Beethoven). Gleiche Harmonie, gleiches melodisches Motiv, völlig unterschiedliche Texturen." },
  { q: "'Kontrapunkt' als motivische Entwicklungstechnik besteht aus:", opts: ["Dem zweimaligen Wiederholen des Motivs", "Dem Hinzufügen einer unabhängigen Stimme, die auf das Motiv antwortet, es imitiert oder kontrastiert — die Polyfonie bereichernd", "Dem Ändern des Tempos", "Dem Umkehren der Intervalle"], a: 1, fb: "Kontrapunkt fügt eine oder mehrere Stimmen hinzu, die mit dem Hauptmotiv dialogisieren. Diese Stimme kann es imitieren (Kanon), in Gegenbewegung antworten oder in Sextparallelen begleiten. Das Werk wird dichter, ohne das Motiv zu modifizieren — Bereicherung durch Addition, nicht durch Transformation." },
  { q: "Die 'Basslinie' als motivische Entwicklung bedeutet:", opts: ["Das Motiv im Bass spielen", "Den Bass in einen selbstständigen melodischen Kontrapunkt transformieren — Terz, Sexte oder Gegenbewegung — der mit dem Motiv dialogisiert", "Den Bass entfernen", "Den Bass in der Oktave verdoppeln"], a: 1, fb: "Anstatt den harmonischen Bass einfach zu verdoppeln, erhält er seine eigene melodische Kontur — eine Basslinie in Gegenbewegung zum Motiv oder in Terz-/Sextparallelen. Diese Technik ist sehr präsent bei Bach (Choräle) und Beethoven (Sonaten): Sie bereichert die Textur, ohne das Motiv zu verändern." },
  { q: "Das Modifizieren der 'Dynamik' eines Motivs (forte → piano) transformiert:", opts: ["Die Tonhöhen", "Die Intensität und den expressiven Charakter — gleiche Melodie, radikal andere emotionale Wirkung", "Den Rhythmus", "Die Tonart"], a: 1, fb: "Dasselbe Motiv fortissimo gespielt ist bedrohlich oder triumphierend; pianissimo wird es geheimnisvoll oder zärtlich. Beethoven nutzt diese Dichotomie systematisch: er präsentiert sein Motiv fortissimo, wiederholt es dann pianissimo — doppelte Affirmation, doppelter Charakter." },
  { q: "Ein Motiv eine Oktave nach oben zu transponieren erzeugt:", opts: ["Denselben Effekt wie in der unteren Oktave", "Leuchtkraft, Dringlichkeit und Klarheit — die hohe Lage wird als heller und intensiver wahrgenommen", "Eine wahrgenommene Verlangsamung", "Einen Tonartenwechsel"], a: 1, fb: "Die hohe Lage schafft Leuchtkraft und Spannung (psychologisch dringlicher wahrgenommen). Die tiefe Oktave schafft Tiefe, Schwere, Autorität. Beethoven verwendet diese Register-Transformation systematisch in seinen Durchführungen — gleiches Motiv, verschiedene Register, kontrastierende dramatische Wirkungen." },
  { q: "Von Legato zu Staccato auf demselben Motiv zu wechseln:", opts: ["Verlangsamt das Motiv", "Ändert die Artikulation — der Charakter wird je nach Kontext scharf, leicht oder nervös, ohne die Tonhöhen anzutasten", "Modifiziert die Intervalle", "Ändert die Harmonie"], a: 1, fb: "Legato = gebundene Noten, kontinuierlicher Fluss, lyrischer oder sanfter Charakter. Staccato = abgesetzte Noten, lebhafter, leichter oder scharfer Charakter. Dasselbe Motiv legato wirkt nostalgisch; staccato spielerisch oder dringend. Artikulation ist einer der feinsten und ausdrucksstärksten Parameter der dynamischen Entwicklung." },
  { q: "Das Ändern des 'Timbres' in der motivischen Entwicklung bedeutet:", opts: ["Den Komponisten zu ändern", "Dasselbe Motiv einem anderen Instrument zu übertragen (Streicher → Blechbläser, Klavier → Orchester) — gleiche Melodie, radikal andere Instrumentalfarbe", "Die Tonart zu ändern", "Den Rhythmus zu modifizieren"], a: 1, fb: "Dasselbe Motiv bei den Streichern wirkt lyrisch; bei den Blechbläsern heroisch; bei der Flöte luftig; beim Klavier fortissimo perkussiv. Das Timbre ist die 'Stimme' des Instruments. In sinfonischen Durchführungen führt Beethoven dasselbe Motiv durch verschiedene Orchesterfamilien — reine Timbre-Transformation, keine Noten." },
  { q: "Die 'Umkehrung' (Inversion der Intervalle) eines Motivs besteht aus:", opts: ["Das Motiv rückwärts spielen", "Jedes Intervall umkehren: ein aufsteigender Terzsprung wird zu einem absteigenden (und umgekehrt)", "Das Motiv doppelt so schnell wiederholen", "Eine Oktave transponieren"], a: 1, fb: "Die Umkehrung spiegelt jedes Intervall. G–G–G–Es (Kleinterz-Fall) wird zu G–G–G–B (Kleinterz-Aufstieg). Die rhythmische Kontur bleibt identisch; das melodische Profil wird gespiegelt. Technik häufig in Bachs Fugen und Beethovens Durchführungen." },
  { q: "Das 'Krebsgangs' (Retrograde) eines Motivs ist:", opts: ["Das Motiv langsamer gespielt", "Das Motiv rückwärts gespielt — von der letzten Note zur ersten", "Das Motiv eine Oktave transponiert", "Das Motiv zweimal wiederholt"], a: 1, fb: "Der Krebsgang kehrt die Notenreihenfolge um: Es–G–G–G ist der Krebsgang von G–G–G–Es (Beethoven). Technik von Bach in Kanons, von Beethoven und von Serialisten verwendet. Kann dem Ohr unkenntlich erscheinen, behält aber logische Kohärenz mit dem Ausgangsmaterial." },
  { q: "Das Hinzufügen von 'Durchgangsnoten' zu einem Motiv:", opts: ["Zerstört das Motiv vollständig", "Bereichert die melodische Kontur, indem Sprünge gefüllt werden — das ursprüngliche Motiv bleibt erkennbar, die Melodie wird fließender", "Ändert den Rhythmus", "Ändert die Tonart"], a: 1, fb: "Durchgangsnoten füllen die Intervalle des Motivs. Ein Terzsprung (C–E) wird zu einem Tonleiterausschnitt (C–D–E). Die rhythmische Kontur kann identisch bleiben. Das Motiv ist melodisch reicher, weniger 'kantig', aber seine ursprüngliche Identität bleibt wahrnehmbar." },
  { q: "Eine 'nicht-rhythmische Transformation' eines Motivs bedeutet:", opts: ["Den Rhythmus identisch zu halten, aber die Tonhöhen entsprechend der Tonleiter zu modifizieren (harmonische Sequenz oder Transposition)", "Nur den Rhythmus zu ändern", "Alle Noten zu entfernen", "Das Motiv umzukehren"], a: 0, fb: "Nicht-rhythmische Transformation bewahrt das Rhythmusmuster des Motivs, verschiebt aber die Tonhöhen entlang der Tonleiter (Tonalsequenz) oder durch exakte Transposition (Realsequenz). Der Rhythmus — oft die stärkste Identität — bleibt erkennbar; die Tonhöhen variieren. Dies ist die harmonische Sequenz." },
  { q: "Warum sind Umkehrung und Krebsgang Transformationen der 'Familie C'?", opts: ["Weil sie die einfachsten sind", "Weil sie die melodische Kontur transformieren, ohne notwendigerweise den Rhythmus zu berühren — Tonhöhen modifiziert, Zeitstruktur erhalten", "Weil sie nach rhythmischen Änderungen angewendet werden", "Weil sie nur die Harmonie modifizieren"], a: 1, fb: "Umkehrung und Krebsgang modifizieren die Tonhöhen und bewahren dabei oft die rhythmische Struktur. Sie gehören zu den melodischen Transformationen (Familie C). Sie sind radikaler als Familie A (Harmonie), aber weniger radikal als Familie D (rhythmische Änderungen)." },
  { q: "Das Weglassen einer Note aus einem Motiv:", opts: ["Zerstört das Motiv vollständig", "Leichtet das Motiv auf — die allgemeine Kontur kann erkennbar bleiben und eine reduzierte oder fragmentierte Version schaffen", "Wird in der Komposition nie verwendet", "Muss immer durch eine andere Note kompensiert werden"], a: 1, fb: "Das Weglassen einer Note schafft eine 'leichtere' Version des Motivs — progressive Liquidationstechnik (Schönbergs Begriff). Das Motiv verliert allmählich seine unverwechselbaren Züge. Beethoven verwendet diese Technik am Ende von Durchführungen: das Motiv fragmentiert sich, bis es sich in der Schlusskadenz auflöst." },
  { q: "'Augmentation' eines Motivs besteht aus:", opts: ["Das Motiv lauter spielen", "Die Dauer jeder Note verdoppeln (oder verdreifachen) — das Motiv verlangsamt sich, gewinnt feierliche Größe", "Eine Oktave transponieren", "Die Intervalle umkehren"], a: 1, fb: "Augmentation verdoppelt jede Dauer: eine Achtel wird zur Viertel, eine Viertel zur Halben. Das Motiv dehnt sich in der Zeit — Zeitlupeneffekt, Feierlichkeit, Größe. Beethoven verwendet sie in Durchführungen, um ein Gefühl der Unausweichlichkeit zu erzeugen." },
  { q: "'Diminution' eines Motivs besteht aus:", opts: ["Das Motiv leiser spielen", "Die Dauer jeder Note teilen — das Motiv beschleunigt sich, wird nervös oder dringend", "Noten entfernen", "Das Motiv umkehren"], a: 1, fb: "Diminution teilt jede Dauer: eine Viertel wird zur Achtel, eine Achtel zur Sechzehntel. Das Motiv beschleunigt sich — Effekt wachsender Spannung, Ungeduld, Dringlichkeit. Technik häufig in Fugendurchführungen (Bach) und Beethovens Liquidationsabschnitten." },
  { q: "Das Ändern des Taktes (3/4 → 4/4) transformiert ein Motiv durch:", opts: ["Hinzufügen von Noten", "Ändern seines metrischen Kontexts — dasselbe Motiv in einem anderen Takt erzeugt ein Gefühl von Leichtigkeit, Ungleichgewicht oder neuer Energie", "Modifizieren seiner Tonhöhen", "Verdoppeln seiner Dauer"], a: 1, fb: "Ein Motiv von 4/4 auf 3/4 zu transponieren gibt ihm einen Walzer-Charakter; von 3/4 auf 2/4 eine Marsch-Energie. Der Taktstrich verschiebt sich relativ zu den Noten — Akzente fallen an anderen Stellen. Chopin verwendet diese Technik in seinem Scherzo Nr. 2." },
  { q: "Warum werden rhythmische Änderungen zuletzt angewendet?", opts: ["Weil sie schwieriger zu schreiben sind", "Weil der Rhythmus oft das markanteste Element des Motivs ist — ihn zu modifizieren ist die radikalste Änderung, die das Motiv unkenntlich machen kann", "Weil sie ein Orchester erfordern", "Weil sie am wenigsten ausdrucksstark sind"], a: 1, fb: "Der Rhythmus ist oft die robusteste DNA eines Motivs — Beethovens ta-ta-ta-TAA ist erkennbar, auch wenn es in eine andere Tonart transponiert wird. Den Rhythmus anzutasten riskiert, die Motividentität zu verlieren. Daher kommen rhythmische Änderungen zuletzt: größte transformative Kraft — und größtes Risiko." },
  { q: "Die 'rhythmische Deregulierung' eines Motivs besteht aus:", opts: ["Das Regularisieren von Synkopen", "Das Verwandeln von Hauptzählzeiten in Synkopen — das Verschieben der Akzente des Motivs, um rhythmische Spannung oder Überraschung zu erzeugen", "Das Verdoppeln der Notendauern", "Das Ändern des Tempos"], a: 1, fb: "Deregulierung erzeugt Synkopen dort, wo das ursprüngliche Motiv Hauptzählzeiten hatte. Der Effekt ist rhythmische Destabilisierung — das Ohr erwartete einen Akzent an einer Stelle, er kommt versetzt. Technik sehr präsent im Jazz (Off-Beat-Phrasierung) und in Beethovens Durchführungen." },
  { q: "Die korrekte Reihenfolge der Anwendung der 4 Familien ist:", opts: ["D → C → B → A (Rhythmus zuerst)", "A → B → C → D (Harmonie zuerst, Rhythmus zuletzt)", "C → A → D → B (Melodisches zuerst)", "Es gibt keine definierte Reihenfolge"], a: 1, fb: "Die Reihenfolge A–B–C–D geht vom weniger zum mehr Radikalen: A (Harmonie/Begleitung) transformiert die Motividentität am wenigsten; D (Rhythmus) am meisten. Wir beginnen mit Transformationen, die das Motiv vollständig erkennbar lassen, und gehen schrittweise zu tiefgreifenderen Transformationen über." },
  { q: "Um eine Transformation anzuwenden, die das Motiv vollständig erkennbar lässt, verwendet man:", opts: ["Familie D (rhythmische Änderungen)", "Familie A (Harmonie und Begleitung) — die melodische Kontur und der Rhythmus bleiben intakt", "Familie C (melodische Transformationen)", "Familien B und D zusammen"], a: 1, fb: "Familie A ist die am wenigsten radikale: Das Ändern der Harmonie oder Textur (Arpeggien, Kontrapunkt, Substitution) lässt das Motiv vollständig erkennbar. Melodie und Rhythmus — seine beiden erkennbarsten Züge — bleiben intakt. Es ist das 'Neueinfärben' des Motivs, nicht seine Transformation." },
  { q: "Wie viele Familien von motivischen Entwicklungstechniken gibt es?", opts: ["3", "4", "5", "7"], a: 1, fb: "Es gibt 4 Familien: A (Harmonie und Begleitung), B (dynamische Gestaltung), C (melodische Transformationen), D (rhythmische Änderungen). Jede Familie gruppiert Techniken ähnlicher Radikalität und wird in dieser Reihenfolge angewendet — von weniger zu mehr transformativ." },
  { q: "In welchem Jahr komponierte Beethoven seine 5. Sinfonie?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "Beethovens 5. Sinfonie wurde 1808 fertiggestellt (gewidmet dem Fürsten Lobkowitz und dem Grafen Razumovsky). Im selben Jahr erschien die 6. Sinfonie (Pastorale). Beethoven befand sich in seiner 'heroischen' Periode — bereits seit Jahren taub, was seine motivische Meisterschaft umso bemerkenswerter macht." },
  { q: "Beethoven wird oft mit welchem ästhetischen Prinzip verbunden?", opts: ["Barocke Ornamentik", "Ökonomie der Mittel — das Maximum aus dem Minimum an motivischem Material zu bauen", "Opernmelodik", "Modale Improvisation"], a: 1, fb: "Ökonomie der Mittel ist das quintessenzielle beethovensche Prinzip: das Maximum aus dem Minimum herausholen. 4 Noten erzeugen eine Sinfonie. Dieser Ansatz stand im Kontrast zum galanten, ornamentierten Stil seiner Vorgänger. Für Beethoven liegt der Reichtum nicht in der Menge des Materials, sondern in der Tiefe seiner Entwicklung." },
  { q: "Zu welcher kompositorischen Epoche gehört Beethoven?", opts: ["Barock (1600–1750)", "Klassik (1750–1820) — mit einem Fuß im Romantik", "Spätromantik (1850–1900)", "Impressionismus (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) ist ein Wendepunkt: Seine frühen Werke gehören zur Wiener Klassik (Haydn, Mozart), aber seine späten Werke (Quartette op.132, Sonate op.111, 9. Sinfonie) antizipieren die Romantik und sogar das 20. Jahrhundert. Er überschreitet Epochenkategorien." },
  { q: "Schönberg analysierte Beethovens Technik insbesondere in:", opts: ["Die Kunst der Fuge", "Fundamentals of Musical Composition — ein Traktat, der Beethovens Phrase, Motiv, Periode und Formen formalisiert", "Das Wohltemperierte Klavier", "Berlioz' Instrumentationslehre"], a: 1, fb: "Schönberg schrieb Fundamentals of Musical Composition an der UCLA in den 1930er–40er Jahren (posthum 1967 veröffentlicht). Sein Traktat analysiert systematisch Beethovens Phrase und motivische Entwicklung — paradoxerweise ist Schönberg auch der Vater der Zwölftontechnik, die Beethovens Tonalität abschafft." },
  { q: "Wie erkennt man ein gutes Ausgangsmotiv?", opts: ["Es muss sehr lang sein", "Es ist kurz, unverwechselbar, einprägsam und flexibel genug, um auf vielfältige Weise transformiert zu werden", "Es muss alle Noten der Tonleiter enthalten", "Es muss Dissonanzen vermeiden"], a: 1, fb: "Ein gutes Motiv kombiniert Kürze (einprägsam), Unverwechselbarkeit (erkennbar unter anderen) und Flexibilität (transformierbar). G–G–G–Es erfüllt alle drei Kriterien. Ein zu komplexes Motiv ist schwer zu transformieren; zu einfach, wird es monoton. Die Balance ist die Kunst des Komponisten." },
  { q: "Was ist der häufigste Fehler mit einem Motiv in der Komposition?", opts: ["Es zu oft zu verwenden", "Das Motiv zu viele Male hintereinander identisch zu wiederholen ohne Transformation — Monotonie stellt sich schnell ein", "Es in andere Tonarten zu transponieren", "Es in verschiedenen Instrumentenfamilien zu verwenden"], a: 1, fb: "Reine Wiederholung ist die Versuchung und die Falle. Ein identisch wiederholtes Motiv verliert nach mehr als zwei Wiederholungen seine Anziehungskraft. Das Ohr erwartet Abwechslung. Die Kunst besteht darin, Wiedererkennung (Kohärenz) zu wahren und gleichzeitig zu erneuern (Vielfalt) — das ist das Paradox der Wiederholung." },
  { q: "Was ist die Wirkung einer 'harmonischen Sequenz' in der motivischen Entwicklung?", opts: ["Das Motiv zu entfernen", "Das Motiv auf aufeinanderfolgenden Stufen der Tonleiter zu wiederholen — der Effekt ist progressive tonale Ausweitung", "Nur das Tempo zu ändern", "Den musikalischen Diskurs zu unterbrechen"], a: 1, fb: "Die harmonische Sequenz wiederholt das Motiv auf jeder Stufe der Tonleiter (I, II, III, IV...). Der Hörer nimmt sowohl Kohärenz (gleiches Motiv) als auch Bewegung (Tonhöhenänderung bei jeder Wiederholung) wahr. Effekt von 'Progression' oder 'Eskalation', sehr wirkungsvoll in der Durchführung." },
  { q: "Wie verbessert die Kenntnis der motivischen Entwicklung das Spiel in der Jazzimprovisation?", opts: ["Sie erlaubt es, mehr Noten zu spielen", "Sie gibt Werkzeuge, um einen kohärenten Diskurs aufzubauen — eine Idee exponieren, sie wiederholen/transformieren, zu einem Höhepunkt entwickeln, schließen", "Sie zwingt, in der Pentatonik zu bleiben", "Sie ersetzt die Kenntnis des Akkordschemas"], a: 1, fb: "Ein Improvisator, der die motivische Entwicklung beherrscht, baut einen 'Diskurs' auf statt eine Notenabfolge. Er exponiert ein Motiv (einige Noten), wiederholt und transformiert es (Familie A, B, C oder D), schafft einen Höhepunkt, schließt dann. Der Hörer folgt der Geschichte. Das ist der Unterschied zwischen 'im' Akkordschema und 'durch' das Akkordschema improvisieren." },
  { q: "Die 'Liquidation' eines Motivs am Ende einer Phrase (Schönberg) erzeugt:", opts: ["Eine Stille", "Eine progressive Auflösung des Motivs — es verliert eines nach dem anderen seine charakteristischen Züge und signalisiert die nahende Kadenz", "Eine Modulation", "Ein Tempowechsel"], a: 1, fb: "Liquidation ist die progressive Erosion des Motivs am Ende einer Phrase. Zuerst werden Rhythmus und Melodie beibehalten, dann nur der Rhythmus, dann fast nichts — die Phrase löst sich in der Kadenz auf. Ein sehr raffiniertes rhetorisches 'Schluss'-Verfahren, das Beethoven in seinen Sonaten perfekt beherrscht." },
  { q: "Das Kombinieren mehrerer Entwicklungstechniken (z.B. Augmentation + harmonische Substitution):", opts: ["Ist in der Komposition verboten", "Erzeugt reichere und komplexere Transformationen — die Familien kombinieren sich frei", "Wird nur im 20. Jahrhundert verwendet", "Löscht die Motividentität vollständig aus"], a: 1, fb: "Die 4 Techniken-Familien kombinieren sich frei. Ein Motiv kann gleichzeitig transponiert werden (Familie C), mit substituierter Harmonie (Familie A) und pianissimo gespielt werden (Familie B). Kombinationen schaffen reichere Transformationen — genau das, was Beethoven in den großen Durchführungen seiner Sonaten und Sinfonien tut." },
];

const questionsIt: Question[] = [
  { q: "Cos'è un motivo musicale?", opts: ["Un accordo di 4 suoni", "La più piccola unità musicale distinta, immediatamente riconoscibile — filo conduttore del discorso musicale", "Una scala completa", "Un accordo di dominante"], a: 1, fb: "Il motivo è la più piccola cellula musicale autonoma e distinta. Contiene un'identità ritmica e/o melodica riconoscibile che verrà ripetuta e trasformata per costruire un discorso musicale coerente. Beethoven costruisce l'intera 5ª Sinfonia da un motivo di sole 4 note." },
  { q: "Qual è il ruolo principale del motivo in una composizione?", opts: ["Fissare il tempo", "Servire da filo conduttore — ripetuto e trasformato, dà coerenza e direzione al discorso musicale", "Indicare la tonalità", "Determinare il numero di misure"], a: 1, fb: "Il motivo è il filo conduttore. La sua ripetizione (stretta o trasformata) crea coerenza: l'ascoltatore riconosce l'idea anche trasformata e segue così il discorso musicale. Senza motivo conduttore, una successione di accordi è 'senza radici' — un elenco senza direzione." },
  { q: "Qual è la differenza tra 'musica di supporto' e 'musica di discorso'?", opts: ["La musica di supporto è più veloce", "La musica di supporto accompagna un'azione esterna; la musica di discorso sviluppa le proprie idee musicali in modo autonomo", "La musica di discorso è più corta", "Non c'è nessuna differenza"], a: 1, fb: "La musica di supporto (film, balletto, pubblicità) serve un'azione esterna — la sua struttura può essere frammentata secondo la narrazione. La musica di discorso (sonata, fuga, standard jazz) sviluppa le proprie idee logicamente, indipendentemente da qualsiasi contesto extra-musicale." },
  { q: "Il 'paradosso della ripetizione' nella composizione musicale significa che:", opts: ["Non bisogna mai ripetere", "La ripetizione è necessaria per la coerenza, ma pericolosa se troppo pura — la monotonia minaccia", "Bisogna sempre ripetere esattamente", "La ripetizione è solo ritmica"], a: 1, fb: "Paradosso centrale: senza ripetizione, nessuna coerenza (l'ascoltatore non riconosce nulla); con troppa ripetizione identica, si installa la monotonia. La soluzione: ripetere trasformando. La varietà nella ripetizione è l'arte stessa dello sviluppo motivico." },
  { q: "Le tre fasi della vita di un motivo sono:", opts: ["Introduzione, sviluppo, coda", "Presentazione → Ripetizione → Evoluzione", "Esposizione, fuga, riesposizione", "Motivo, tema, periodo"], a: 1, fb: "Un motivo segue tre fasi retoriche: Presentazione (stabilire l'identità), Ripetizione (ancorare il motivo nell'orecchio), Evoluzione (trasformare, sviluppare, combinare). Questa traiettoria si applica alla scala della frase (8 misure), del movimento e dell'intera opera." },
  { q: "Quanti elementi costitutivi definiscono un motivo?", opts: ["2 (melodia e ritmo)", "3 (melodia, ritmo, armonia)", "5 (intervalli, ritmo, armonia, accompagnamento, dinamica)", "7 (uno per nota)"], a: 2, fb: "Cinque elementi costituiscono un motivo: (1) intervalli (contorno melodico), (2) ritmo (schema di durate), (3) armonia (accordi di sostegno), (4) accompagnamento (texture), (5) dinamica (sfumature e articolazione). Ogni elemento può essere modificato indipendentemente durante lo sviluppo." },
  { q: "Tra i 5 elementi di un motivo, quale è spesso il più immediatamente riconoscibile?", opts: ["La melodia (intervalli)", "Il ritmo — il suo schema è spesso identificabile anche se le altezze cambiano", "L'armonia", "La dinamica"], a: 1, fb: "Il ritmo è spesso l'elemento più distintivo. Nel motivo ta-ta-ta-TAA di Beethoven (3 crome + nera), è riconoscibile anche se trasposto in un'altra tonalità o suonato da uno strumento diverso. Il ritmo è il DNA temporale del motivo." },
  { q: "L'elemento 'accompagnamento' di un motivo designa:", opts: ["La melodia principale", "La texture che circonda il motivo: arpeggi, accordi in blocco, linea di basso indipendente", "Le sfumature dinamiche", "Il tempo"], a: 1, fb: "L'accompagnamento è la texture musicale che circonda il motivo melodico. Lo stesso motivo può suonare in modo radicalmente diverso a seconda che sia accompagnato da arpeggi (leggerezza), accordi in blocco (solidità) o da una linea di basso in contrappunto (ricchezza polifonica)." },
  { q: "L'elemento 'dinamica' di un motivo include:", opts: ["Solo le altezze delle note", "Le sfumature (forte/piano), l'articolazione (legato/staccato) e l'attacco — l'espressione fisica del motivo", "Il numero di ripetizioni", "La tonalità del brano"], a: 1, fb: "La dinamica raggruppa le sfumature (forte, piano, crescendo), l'articolazione (legato, staccato, accento) e il tipo di attacco. Lo stesso motivo suonato pianissimo legato vs fortissimo staccato: due caratteri completamente diversi, senza cambiare una sola nota." },
  { q: "Perché gli intervalli sono un elemento costitutivo del motivo?", opts: ["Perché fissano il tempo", "Perché i salti melodici caratteristici (terza, quinta, tritono) creano l'identità melodica distintiva del motivo", "Perché indicano il metro", "Perché sono sempre uguali in tutti i motivi"], a: 1, fb: "Gli intervalli sono l'impronta melodica del motivo. La caduta di terza minore (Sol–Mib) nel motivo di Beethoven è immediatamente riconoscibile. Un motivo costruito su un tritono suonerà teso; su una terza maggiore, brillante. Gli intervalli fissano il carattere melodico." },
  { q: "Quale motivo usa Beethoven nella sua 5ª Sinfonia (1808)?", opts: ["4 note discendenti per semitoni", "3 note ripetute + una caduta di terza minore (Sol–Sol–Sol–Mib, ta-ta-ta-TAA)", "Un arpeggio di Do maggiore", "Una scala ascendente"], a: 1, fb: "Sol–Sol–Sol–Mib: 3 note ripetute identicamente + caduta di terza minore. Questo motivo è il germe dell'intera 5ª Sinfonia. Beethoven lo frammenta, lo traspone, lo aumenta nei 4 movimenti — dimostrazione assoluta dell'economia dei mezzi." },
  { q: "Cos'è un 'leitmotiv' in Wagner?", opts: ["Un tempo particolare", "Un motivo ricorrente associato a un personaggio o un'idea drammatica — trasformato secondo il contesto", "Un accordo di dominante", "Una fuga per orchestra"], a: 1, fb: "Wagner associa nelle sue opere un motivo musicale (leitmotiv) a ogni personaggio, concetto o oggetto drammatico. Il motivo della spada di Sigfrido ritorna trasformato secondo la situazione — glorioso nel trionfo, cupo nel pericolo. È la forma motivica estesa alla scala di un'intera opera." },
  { q: "Come John Williams eredita la tecnica di Wagner in Star Wars?", opts: ["Usa le stesse armonie", "Associa un leitmotiv a ogni personaggio (tema della Forza, marcia imperiale) trasformandolo secondo il contesto drammatico", "Copia i ritmi di Wagner", "Usa gli stessi strumenti"], a: 1, fb: "Williams eredita direttamente da Wagner: ogni personaggio ha il suo motivo. Il tema della Forza — tranquillo e luminoso — diventa la Marcia Imperiale per Darth Vader, con lo stesso contorno melodico ma un'armonizzazione radicalmente diversa (minore, ottoni, dinamica forte). Stessa tecnica, un secolo dopo." },
  { q: "Ciò che rende efficace il motivo di Beethoven (5ª Sinfonia) è:", opts: ["La sua lunghezza — più di 8 note", "La sua brevità e distintività: solo 4 note, con un ritmo e un intervallo immediatamente memorabili", "La sua complessità armonica", "La sua rara orchestrazione"], a: 1, fb: "La forza del motivo sta nella sua economia. 4 note: 3 ripetute (insistenza) + 1 caduta di terza minore (risoluzione discendente). Questa semplicità lo rende universalmente memorabile e infinitamente trasformabile. Beethoven ne ricava 20 minuti di sinfonia — economia massima, espressività massima." },
  { q: "La tecnica del leitmotiv è notevolmente usata da:", opts: ["Bach nelle sue fughe", "Wagner e, più tardi, John Williams nelle sue musiche da film", "Chopin nei suoi notturni", "Debussy nei suoi preludi"], a: 1, fb: "Wagner sviluppa il leitmotiv nelle sue opere (L'Anello del Nibelungo, Tristano e Isotta). Questa tecnica passa nel cinema attraverso Korngold, Herrmann e soprattutto John Williams — che riconosce apertamente il suo debito verso Wagner in Star Wars." },
  { q: "La famiglia A (armonia e accompagnamento) viene applicata per prima perché:", opts: ["È più facile", "È la trasformazione meno radicale — l'identità melodica e ritmica del motivo rimane intatta", "Dà il miglior risultato", "È la più rapida da realizzare"], a: 1, fb: "Modificando l'armonia o la texture dell'accompagnamento, si trasforma il 'colore' del motivo senza toccare la sua identità melodia-ritmo. L'ascoltatore riconosce pienamente il motivo — il cambiamento è sottile. Ecco perché questa famiglia viene applicata per prima: effetto notevole, rischio minimo di perdita d'identità." },
  { q: "La 'sostituzione armonica' nello sviluppo motivico consiste in:", opts: ["Cambiare il motivo melodico", "Sostituire un accordo con un altro della stessa funzione o colore (I → VI, V7 → SubV) sotto lo stesso motivo", "Cambiare la tonalità del brano", "Eliminare accordi"], a: 1, fb: "La sostituzione armonica cambia gli accordi che sostengono il motivo senza toccare le sue note. Sostituire I con VI (sostituzione diatonica) dà un colore più morbido; V7 con SubV (sostituzione del tritono) produce un basso cromatico. Il motivo rimane riconoscibile, il colore cambia completamente." },
  { q: "Trasformare l'accompagnamento in 'arpeggi' piuttosto che in 'accordi in blocco' modifica:", opts: ["Le note del motivo", "La texture — il modo in cui gli accordi vengono dispiegati nel tempo, creando leggerezza o movimento", "La tonalità", "Il ritmo del motivo"], a: 1, fb: "Gli arpeggi scompongono gli accordi in note successive — creando movimento e leggerezza (Chopin). Gli accordi in blocco creano solidità e impatto (Beethoven). Stessa armonia, stesso motivo melodico, texture completamente diverse." },
  { q: "Il 'contrappunto' come tecnica di sviluppo motivico consiste in:", opts: ["Ripetere il motivo due volte", "Aggiungere una voce indipendente che risponde, imita o contrasta con il motivo — arricchendo la polifonia", "Cambiare il tempo", "Invertire gli intervalli"], a: 1, fb: "Il contrappunto aggiunge una o più voci che dialogano con il motivo principale. Questa voce può imitarlo (canone), rispondergli in moto contrario, o accompagnarlo in seste parallele. L'opera diventa più densa senza modificare il motivo — arricchimento per addizione, non per trasformazione." },
  { q: "La 'linea di basso' come sviluppo motivico significa:", opts: ["Suonare il motivo al basso", "Trasformare il basso in un contrappunto melodico indipendente — terza, sesta o moto contrario — che dialoga con il motivo", "Eliminare il basso", "Raddoppiare il basso all'ottava"], a: 1, fb: "Invece di raddoppiare semplicemente il basso armonico, gli si dà un proprio contorno melodico — una linea di basso in moto contrario al motivo, o in terze/seste parallele. Tecnica molto presente in Bach (corali) e Beethoven (sonate): arricchisce la texture senza alterare il motivo." },
  { q: "Modificare le 'sfumature' di un motivo (forte → piano) trasforma:", opts: ["Le altezze delle note", "L'intensità e il carattere espressivo — stessa melodia, impatto emotivo radicalmente diverso", "Il ritmo", "La tonalità"], a: 1, fb: "Lo stesso motivo suonato fortissimo è minaccioso o trionfale; pianissimo diventa misterioso o tenero. Beethoven sfrutta sistematicamente questa dicotomia: presenta il suo motivo fortissimo, poi lo ripete pianissimo — doppia affermazione, doppio carattere." },
  { q: "Trasporre un motivo di un'ottava verso l'alto produce:", opts: ["Lo stesso effetto che all'ottava inferiore", "Luminosità, urgenza e chiarezza — il registro acuto è percepito come più brillante e intenso", "Un rallentamento percepito", "Un cambio di tonalità"], a: 1, fb: "Il registro acuto crea luminosità e tensione (percepita come più urgente psicologicamente). L'ottava grave crea profondità, gravità, autorità. Beethoven usa questa trasformazione di registro sistematicamente nei suoi sviluppi — stesso motivo, registri diversi, effetti drammatici contrastanti." },
  { q: "Passare da legato a staccato sullo stesso motivo:", opts: ["Rallenta il motivo", "Cambia l'articolazione — il carattere diventa incisivo, leggero o nervoso secondo il contesto, senza toccare le altezze", "Modifica gli intervalli", "Cambia l'armonia"], a: 1, fb: "Legato = note legate, flusso continuo, carattere lirico o morbido. Staccato = note staccate, carattere vivace, leggero o incisivo. Lo stesso motivo in legato sembra nostalgico; in staccato, giocoso o urgente. L'articolazione è uno dei parametri più fini ed espressivi dello sviluppo dinamico." },
  { q: "Cambiare il 'timbro' in uno sviluppo motivico significa:", opts: ["Cambiare il compositore", "Affidare lo stesso motivo a uno strumento diverso (violini → ottoni, pianoforte → orchestra) — stessa melodia, colore strumentale radicalmente diverso", "Cambiare la tonalità", "Modificare il ritmo"], a: 1, fb: "Lo stesso motivo ai violini sembra lirico; agli ottoni, eroico; al flauto, aereo; al pianoforte fortissimo, percussivo. Il timbro è la 'voce' dello strumento. Negli sviluppi sinfonici, Beethoven passa lo stesso motivo attraverso diverse famiglie orchestrali — pura trasformazione di timbro, non di note." },
  { q: "L''inversione' (inversione degli intervalli) di un motivo consiste in:", opts: ["Suonare il motivo al contrario", "Invertire ogni intervallo: una salita di terza diventa una discesa di terza (e viceversa)", "Ripetere il motivo due volte più velocemente", "Trasporre di un'ottava"], a: 1, fb: "L'inversione specchia ogni intervallo. Sol–Sol–Sol–Mib (caduta di terza minore) diventa Sol–Sol–Sol–Sib (salita di terza minore). Il contorno ritmico rimane identico; il profilo melodico è invertito. Tecnica frequente nelle fughe di Bach e negli sviluppi di Beethoven." },
  { q: "Il 'moto retrogrado' di un motivo è:", opts: ["Il motivo suonato più lentamente", "Il motivo suonato al contrario — dall'ultima nota alla prima", "Il motivo trasposto di un'ottava", "Il motivo ripetuto due volte"], a: 1, fb: "Il moto retrogrado inverte l'ordine delle note: Mib–Sol–Sol–Sol è il retrogrado di Sol–Sol–Sol–Mib (Beethoven). Tecnica usata da Bach nei canoni, da Beethoven e dai serialisti. Può sembrare irriconoscibile all'orecchio ma mantiene coerenza logica con il materiale originale." },
  { q: "Aggiungere 'note di passaggio' a un motivo:", opts: ["Distrugge il motivo completamente", "Arricchisce il contorno melodico riempiendo i salti — il motivo originale rimane riconoscibile, la melodia diventa più fluida", "Cambia il ritmo", "Cambia la tonalità"], a: 1, fb: "Le note di passaggio riempiono gli intervalli del motivo. Un salto di terza (Do–Mi) diventa un frammento di scala (Do–Re–Mi). Il contorno ritmico può rimanere identico. Il motivo è più ricco melodicamente, meno 'angoloso', ma la sua identità di partenza rimane percepibile." },
  { q: "Una 'trasformazione non ritmica' di un motivo significa:", opts: ["Conservare il ritmo identico ma modificare le altezze secondo la scala (marcia armonica o trasposizione)", "Cambiare solo il ritmo", "Eliminare tutte le note", "Invertire il motivo"], a: 0, fb: "La trasformazione non ritmica conserva lo schema ritmico del motivo ma fa scorrere le altezze lungo la scala (sequenza tonale) o per trasposizione esatta (sequenza reale). Il ritmo — spesso l'identità più forte — rimane riconoscibile; le altezze variano. Questa è la marcia armonica o sequenza." },
  { q: "Perché inversione e retrogrado sono trasformazioni della 'famiglia C'?", opts: ["Perché sono le più semplici", "Perché trasformano il contorno melodico senza necessariamente toccare il ritmo — altezze modificate, struttura temporale preservata", "Perché si applicano dopo le alterazioni ritmiche", "Perché modificano solo l'armonia"], a: 1, fb: "Inversione e retrogrado modificano le altezze mantenendo spesso la struttura ritmica. Appartengono alle trasformazioni melodiche (famiglia C). Sono più radicali della famiglia A (armonia) ma meno radicali della famiglia D (alterazioni ritmiche)." },
  { q: "L'omissione di una nota da un motivo:", opts: ["Distrugge completamente il motivo", "Alleggerisce il motivo — il contorno generale può rimanere riconoscibile, creando una versione ridotta o frammentata", "Non viene mai usata in composizione", "Deve sempre essere compensata da un'altra nota"], a: 1, fb: "Omettere una nota crea una versione 'alleggerita' del motivo — tecnica di liquidazione progressiva (termine di Schoenberg). Il motivo perde progressivamente i suoi tratti distintivi. Beethoven usa questa tecnica alla fine degli sviluppi: il motivo si frammenta fino a dissolversi nella cadenza finale." },
  { q: "L''aumentazione' di un motivo consiste in:", opts: ["Suonare il motivo più forte", "Raddoppiare (o triplicare) la durata di ogni nota — il motivo rallenta, acquista un'ampiezza solenne", "Trasporre di un'ottava", "Invertire gli intervalli"], a: 1, fb: "L'aumentazione raddoppia ogni durata: una croma diventa una nera, una nera diventa una bianca. Il motivo si estende nel tempo — effetto di rallentamento, solennità, grandiosità. Beethoven la usa negli sviluppi per creare un senso di inevitabilità." },
  { q: "La 'diminuzione' di un motivo consiste in:", opts: ["Suonare il motivo più piano", "Dividere la durata di ogni nota — il motivo accelera, diventa nervoso o urgente", "Eliminare note", "Invertire il motivo"], a: 1, fb: "La diminuzione divide ogni durata: una nera diventa una croma, una croma una semicroma. Il motivo accelera — effetto di tensione crescente, impazienza, urgenza. Tecnica frequente negli sviluppi di fughe (Bach) e nelle sezioni di liquidazione di Beethoven." },
  { q: "Il cambiamento di metro (3/4 → 4/4) trasforma un motivo:", opts: ["Aggiungendogli note", "Cambiando il suo contesto metrico — lo stesso motivo in un metro diverso crea un senso di leggerezza, squilibrio o nuova energia", "Modificando le sue altezze", "Raddoppiando la sua durata"], a: 1, fb: "Trasporre un motivo da 4/4 a 3/4 gli dà un'aria da valzer; da 3/4 a 2/4, un'energia di marcia. La stanghetta si sposta rispetto alle note — gli accenti cadono in altri punti. Chopin usa questa tecnica nel suo Scherzo n.2." },
  { q: "Perché le alterazioni ritmiche vengono applicate per ultime?", opts: ["Perché sono più difficili da scrivere", "Perché il ritmo è spesso l'elemento più distintivo del motivo — modificarlo è il cambiamento più radicale, con il rischio di renderlo irriconoscibile", "Perché richiedono un'orchestra", "Perché sono le meno espressive"], a: 1, fb: "Il ritmo è spesso il DNA più robusto di un motivo — il ta-ta-ta-TAA di Beethoven è riconoscibile anche trasposto in un'altra tonalità. Toccare il ritmo rischia di perdere l'identità del motivo. Ecco perché le alterazioni ritmiche vengono per ultime: maggiore potere trasformativo — e maggiore rischio." },
  { q: "La 'deregolamentazione' ritmica di un motivo consiste in:", opts: ["Regolarizzare le sincopi", "Trasformare i tempi forti in sincopi — spostare gli accenti del motivo per creare tensione o sorpresa ritmica", "Raddoppiare la durata delle note", "Cambiare il tempo"], a: 1, fb: "La deregolamentazione crea sincopi dove il motivo originale aveva tempi forti. L'effetto è di destabilizzazione ritmica — l'orecchio si aspettava un accento in un punto, arriva spostato. Tecnica molto presente nel jazz (fraseggio off-beat) e negli sviluppi beethoveniani." },
  { q: "L'ordine corretto di applicazione delle 4 famiglie è:", opts: ["D → C → B → A (ritmo per primo)", "A → B → C → D (armonia per prima, ritmo per ultimo)", "C → A → D → B (melodico per primo)", "Non esiste un ordine definito"], a: 1, fb: "L'ordine A–B–C–D va da meno a più radicale: A (armonia/accompagnamento) trasforma meno l'identità del motivo; D (ritmo) la trasforma di più. Si inizia con le trasformazioni che lasciano il motivo pienamente riconoscibile, per passare progressivamente a trasformazioni più profonde." },
  { q: "Per applicare una trasformazione che lasci il motivo pienamente identificabile, si usa:", opts: ["La famiglia D (alterazioni ritmiche)", "La famiglia A (armonia e accompagnamento) — il contorno melodico e il ritmo rimangono intatti", "La famiglia C (trasformazioni melodiche)", "Le famiglie B e D insieme"], a: 1, fb: "La famiglia A è la meno radicale: cambiare l'armonia o la texture (arpeggi, contrappunto, sostituzione) lascia il motivo completamente riconoscibile. La melodia e il ritmo — i suoi due tratti più identificabili — rimangono intatti. È il 'ricolorare' del motivo, non la sua trasformazione." },
  { q: "Quante famiglie di tecniche di sviluppo motivico esistono?", opts: ["3", "4", "5", "7"], a: 1, fb: "Esistono 4 famiglie: A (armonia e accompagnamento), B (disposizione dinamica), C (trasformazioni melodiche), D (alterazioni ritmiche). Ogni famiglia raggruppa tecniche di un grado di radicalità simile e viene applicata in questo ordine — da meno a più trasformativa." },
  { q: "In quale anno Beethoven compose la sua 5ª Sinfonia?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "La 5ª Sinfonia di Beethoven fu completata nel 1808 (dedicata al principe Lobkowitz e al conte Razumovsky). Lo stesso anno uscì la 6ª Sinfonia (Pastorale). Beethoven era allora nel pieno del suo periodo 'eroico' — già sordo da diversi anni, il che rende la sua padronanza motivica ancora più straordinaria." },
  { q: "Beethoven è spesso associato a quale principio estetico?", opts: ["L'ornamentazione barocca", "L'economia dei mezzi — costruire il massimo a partire dal minimo di materiale motivico", "La melodia operistica", "L'improvvisazione modale"], a: 1, fb: "L'economia dei mezzi è il principio beethoveniano per eccellenza: trarre il massimo dal minimo. 4 note generano una sinfonia. Questo approccio contrastava con lo stile galante e ornamentale dei suoi predecessori. Per Beethoven, la ricchezza non sta nella quantità di materiale, ma nella profondità del suo sviluppo." },
  { q: "A quale epoca compositiva appartiene Beethoven?", opts: ["Barocco (1600–1750)", "Classicismo (1750–1820) — con un piede nel Romanticismo", "Romanticismo tardivo (1850–1900)", "Impressionismo (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) è un punto di svolta: le sue prime opere si inscrivono nel classicismo viennese (Haydn, Mozart), ma le opere tarde (Quartetti op.132, Sonata op.111, 9ª Sinfonia) anticipano il Romanticismo e persino il XX secolo. Trascende le categorie di epoca." },
  { q: "Schoenberg analizzò notevolmente la tecnica di Beethoven in:", opts: ["L'Arte della Fuga", "Fundamentals of Musical Composition — trattato che formalizza la frase, il motivo, il periodo e le forme beethoveniane", "Il Clavicembalo ben temperato", "Il Trattato di orchestrazione di Berlioz"], a: 1, fb: "Schoenberg redasse Fundamentals of Musical Composition alla UCLA negli anni 1930–40 (pubblicato postumo nel 1967). Il suo trattato analizza sistematicamente la frase e lo sviluppo motivico di Beethoven — paradossalmente, Schoenberg è anche il padre del dodecafonismo, che abolisce la tonalità beethoveniana." },
  { q: "Come si riconosce un buon motivo di partenza?", opts: ["Deve essere molto lungo", "È breve, distintivo, memorabile e sufficientemente flessibile per essere trasformato in molteplici modi", "Deve contenere tutte le note della scala", "Deve evitare le dissonanze"], a: 1, fb: "Un buon motivo combina brevità (memorabile), distintività (riconoscibile tra gli altri) e flessibilità (trasformabile). Sol–Sol–Sol–Mib soddisfa tutti e tre i criteri. Un motivo troppo complesso è difficile da trasformare; troppo semplice, diventa monotono. L'equilibrio è l'arte del compositore." },
  { q: "Qual è l'errore più comune con un motivo in composizione?", opts: ["Usarlo troppo spesso", "Ripetere il motivo identicamente troppe volte di seguito senza trasformazione — la monotonia si installa rapidamente", "Trasporlo in altre tonalità", "Usarlo in diverse famiglie strumentali"], a: 1, fb: "La ripetizione pura è la tentazione e la trappola. Un motivo ripetuto identicamente più di due volte perde il suo potere di attrazione. L'orecchio si aspetta varietà. L'arte consiste nel mantenere il riconoscimento (coerenza) rinnovando al contempo (varietà) — questo è il paradosso della ripetizione." },
  { q: "Qual è l'effetto di una 'marcia armonica' nello sviluppo di un motivo?", opts: ["Eliminare il motivo", "Ripetere il motivo a gradi successivi della scala — l'effetto è di espansione tonale progressiva", "Cambiare solo il tempo", "Arrestare il discorso musicale"], a: 1, fb: "La marcia armonica ripete il motivo a ogni grado della scala (I, II, III, IV...). L'ascoltatore percepisce sia la coerenza (stesso motivo) che il movimento (cambio di altezza a ogni ripetizione). Effetto di 'progressione' o 'escalation' molto efficace nello sviluppo." },
  { q: "Nell'improvvisazione jazz, come la conoscenza dello sviluppo motivico migliora il suono?", opts: ["Permette di suonare più note", "Fornisce strumenti per costruire un discorso coerente — esporre un'idea, ripeterla/trasformarla, svilupparla verso un climax, concludere", "Obbliga a rimanere nella scala pentatonica", "Sostituisce la conoscenza della griglia armonica"], a: 1, fb: "Un improvvisatore che padroneggia lo sviluppo motivico costruisce un 'discorso' piuttosto che una successione di note. Espone un motivo (alcune note), lo ripete e lo trasforma (famiglia A, B, C o D), crea un climax, poi conclude. L'ascoltatore segue la storia. Questa è la differenza tra improvvisare 'dentro' la griglia e improvvisare 'attraverso' di essa." },
  { q: "La 'liquidazione' di un motivo alla fine di una frase (Schoenberg) produce:", opts: ["Un silenzio", "Una dissoluzione progressiva del motivo — perde i suoi tratti distintivi uno per uno, segnalando che la cadenza si avvicina", "Una modulazione", "Un cambio di tempo"], a: 1, fb: "La liquidazione è l'erosione progressiva del motivo alla fine di una frase. Prima si conservano ritmo e melodia, poi solo il ritmo, poi quasi nulla — la frase si dissolve nella cadenza. Procedimento retorico molto sofisticato di 'conclusione' che Beethoven padroneggia perfettamente nelle sue sonate." },
  { q: "La combinazione di più tecniche di sviluppo (es. aumentazione + sostituzione armonica):", opts: ["È vietata in composizione", "Produce trasformazioni più ricche e complesse — le famiglie si combinano liberamente", "Viene usata solo nel XX secolo", "Cancella completamente l'identità del motivo"], a: 1, fb: "Le 4 famiglie di tecniche si combinano liberamente. Un motivo può essere simultaneamente trasposto (famiglia C), con armonia sostituita (famiglia A) e suonato pianissimo (famiglia B). Le combinazioni creano trasformazioni più ricche — esattamente ciò che fa Beethoven nei grandi sviluppi delle sue sonate e sinfonie." },
];

const questionsPt: Question[] = [
  { q: "O que é um motivo musical?", opts: ["Um acorde de 4 sons", "A menor unidade musical distinta, imediatamente reconhecível — fio condutor do discurso musical", "Uma escala completa", "Um acorde de dominante"], a: 1, fb: "O motivo é a menor célula musical autónoma e distinta. Contém uma identidade rítmica e/ou melódica reconhecível que será repetida e transformada para construir um discurso musical coerente. Beethoven constrói toda a sua 5ª Sinfonia a partir de um motivo de apenas 4 notas." },
  { q: "Qual é o papel principal do motivo numa composição?", opts: ["Fixar o andamento", "Servir de fio condutor — repetido e transformado, dá coerência e direção ao discurso musical", "Indicar a tonalidade", "Determinar o número de compassos"], a: 1, fb: "O motivo é o fio condutor. A sua repetição (estrita ou transformada) cria coerência: o ouvinte reconhece a ideia mesmo transformada e segue assim o discurso musical. Sem motivo condutor, uma sucessão de acordes fica 'sem chão' — uma lista sem direção." },
  { q: "Qual é a diferença entre 'música de suporte' e 'música de discurso'?", opts: ["A música de suporte é mais rápida", "A música de suporte acompanha uma ação exterior; a música de discurso desenvolve as suas próprias ideias musicais de forma autónoma", "A música de discurso é mais curta", "Não há nenhuma diferença"], a: 1, fb: "A música de suporte (cinema, ballet, publicidade) serve uma ação exterior — a sua estrutura pode ser fragmentada segundo a narrativa. A música de discurso (sonata, fuga, standard de jazz) desenvolve as suas próprias ideias logicamente, independentemente de qualquer contexto extra-musical." },
  { q: "O 'paradoxo da repetição' na composição musical significa que:", opts: ["Nunca se deve repetir", "A repetição é necessária para a coerência, mas perigosa se demasiado pura — a monotonia ameaça", "Deve-se sempre repetir exatamente", "A repetição é apenas rítmica"], a: 1, fb: "Paradoxo central: sem repetição, não há coerência (o ouvinte não reconhece nada); com demasiada repetição idêntica, instala-se a monotonia. A solução: repetir transformando. A variedade na repetição é a própria arte do desenvolvimento motívico." },
  { q: "As três fases da vida de um motivo são:", opts: ["Introdução, desenvolvimento, coda", "Apresentação → Repetição → Evolução", "Exposição, fuga, reexposição", "Motivo, tema, período"], a: 1, fb: "Um motivo segue três fases retóricas: Apresentação (estabelecer a identidade), Repetição (ancorar o motivo no ouvido), Evolução (transformar, desenvolver, combinar). Esta trajetória aplica-se à escala da frase (8 compassos), do andamento e de toda a obra." },
  { q: "Quantos elementos constitutivos definem um motivo?", opts: ["2 (melodia e ritmo)", "3 (melodia, ritmo, harmonia)", "5 (intervalos, ritmo, harmonia, acompanhamento, dinâmica)", "7 (um por nota)"], a: 2, fb: "Cinco elementos constituem um motivo: (1) intervalos (contorno melódico), (2) ritmo (esquema de durações), (3) harmonia (acordes de suporte), (4) acompanhamento (textura), (5) dinâmica (nuances e articulação). Cada elemento pode ser modificado independentemente durante o desenvolvimento." },
  { q: "Entre os 5 elementos de um motivo, qual é frequentemente o mais imediatamente reconhecível?", opts: ["A melodia (intervalos)", "O ritmo — o seu padrão é frequentemente identificável mesmo quando as alturas mudam", "A harmonia", "A dinâmica"], a: 1, fb: "O ritmo é frequentemente o elemento mais distintivo. No motivo ta-ta-ta-TAA de Beethoven (3 colcheias + semínima), é reconhecível mesmo transposto para outra tonalidade ou tocado por um instrumento diferente. O ritmo é o ADN temporal do motivo." },
  { q: "O elemento 'acompanhamento' de um motivo designa:", opts: ["A melodia principal", "A textura que rodeia o motivo: arpejos, acordes em bloco, linha de baixo independente", "As nuances dinâmicas", "O andamento"], a: 1, fb: "O acompanhamento é a textura musical que rodeia o motivo melódico. O mesmo motivo pode soar de forma radicalmente diferente conforme acompanhado por arpejos (leveza), acordes em bloco (solidez) ou uma linha de baixo em contraponto (riqueza polifónica)." },
  { q: "O elemento 'dinâmica' de um motivo inclui:", opts: ["Apenas as alturas das notas", "As nuances (forte/piano), a articulação (legato/staccato) e o ataque — a expressão física do motivo", "O número de repetições", "A tonalidade da peça"], a: 1, fb: "A dinâmica agrupa as nuances (forte, piano, crescendo), a articulação (legato, staccato, acento) e o tipo de ataque. O mesmo motivo tocado pianissimo legato vs fortissimo staccato: dois caracteres completamente diferentes, sem mudar uma única nota." },
  { q: "Por que razão os intervalos são um elemento constitutivo do motivo?", opts: ["Porque fixam o andamento", "Porque os saltos melódicos característicos (terça, quinta, trítono) criam a identidade melódica distintiva do motivo", "Porque indicam o compasso", "Porque são sempre iguais em todos os motivos"], a: 1, fb: "Os intervalos são a impressão digital melódica do motivo. A queda de terça menor (Sol–Mib) no motivo de Beethoven é imediatamente reconhecível. Um motivo construído sobre um trítono soará tenso; sobre uma terça maior, brilhante. Os intervalos fixam o carácter melódico." },
  { q: "Que motivo usa Beethoven na sua 5ª Sinfonia (1808)?", opts: ["4 notas descendentes por semitons", "3 notas repetidas + uma queda de terça menor (Sol–Sol–Sol–Mib, ta-ta-ta-TAA)", "Um arpejo de Dó maior", "Uma escala ascendente"], a: 1, fb: "Sol–Sol–Sol–Mib: 3 notas repetidas identicamente + queda de terça menor. Este motivo é o germe de toda a 5ª Sinfonia. Beethoven fragmenta-o, transpõe-o, aumenta-o nos 4 andamentos — demonstração absoluta da economia de meios." },
  { q: "O que é um 'leitmotiv' em Wagner?", opts: ["Um andamento particular", "Um motivo recorrente associado a uma personagem ou ideia dramática — transformado segundo o contexto", "Um acorde de dominante", "Uma fuga para orquestra"], a: 1, fb: "Wagner associa nas suas óperas um motivo musical (leitmotiv) a cada personagem, conceito ou objeto dramático. O motivo da espada de Siegfried regressa transformado segundo a situação — glorioso no triunfo, sombrio no perigo. É a forma motívica alargada à escala de uma ópera inteira." },
  { q: "Como é que John Williams herda a técnica de Wagner em Star Wars?", opts: ["Usa as mesmas harmonias", "Associa um leitmotiv a cada personagem (tema da Força, marcha imperial) transformando-o segundo o contexto dramático", "Copia os ritmos de Wagner", "Usa os mesmos instrumentos"], a: 1, fb: "Williams herda diretamente de Wagner: cada personagem tem o seu motivo. O tema da Força — tranquilo e luminoso — torna-se a Marcha Imperial para Darth Vader, com o mesmo contorno melódico mas uma harmonização radicalmente diferente (menor, metais, dinâmica forte). Mesma técnica, um século depois." },
  { q: "O que torna eficaz o motivo de Beethoven (5ª Sinfonia) é:", opts: ["O seu comprimento — mais de 8 notas", "A sua brevidade e distintividade: apenas 4 notas, com um ritmo e um intervalo imediatamente memoráveis", "A sua complexidade harmónica", "A sua rara orquestração"], a: 1, fb: "A força do motivo está na sua economia. 4 notas: 3 repetidas (insistência) + 1 queda de terça menor (resolução descendente). Esta simplicidade torna-o universalmente memorável e infinitamente transformável. Beethoven retira disso 20 minutos de sinfonia — economia máxima, expressividade máxima." },
  { q: "A técnica do leitmotiv é notavelmente usada por:", opts: ["Bach nas suas fugas", "Wagner e, mais tarde, John Williams nas suas músicas de filme", "Chopin nos seus nocturnos", "Debussy nos seus prelúdios"], a: 1, fb: "Wagner desenvolve o leitmotiv nas suas óperas (O Anel do Nibelungo, Tristão e Isolda). Esta técnica passa para o cinema através de Korngold, Herrmann e sobretudo John Williams — que reconhece abertamente a sua dívida para com Wagner em Star Wars." },
  { q: "A família A (harmonia e acompanhamento) é aplicada primeiro porque:", opts: ["É mais fácil", "É a transformação menos radical — a identidade melódica e rítmica do motivo permanece intacta", "Dá o melhor resultado", "É a mais rápida de realizar"], a: 1, fb: "Ao modificar a harmonia ou a textura do acompanhamento, transforma-se a 'cor' do motivo sem tocar na sua identidade melodia-ritmo. O ouvinte reconhece plenamente o motivo — a mudança é subtil. Por isso esta família é aplicada primeiro: efeito notável, risco mínimo de perda de identidade." },
  { q: "A 'substituição harmónica' no desenvolvimento motívico consiste em:", opts: ["Mudar o motivo melódico", "Substituir um acorde por outro da mesma função ou cor (I → VI, V7 → SubV) sob o mesmo motivo", "Mudar a tonalidade da peça", "Suprimir acordes"], a: 1, fb: "A substituição harmónica muda os acordes que sustentam o motivo sem tocar nas notas do motivo. Substituir I por VI (substituição diatónica) dá uma cor mais suave; V7 por SubV (substituição de trítono) produz um baixo cromático. O motivo permanece reconhecível, a cor muda completamente." },
  { q: "Transformar o acompanhamento em 'arpejos' em vez de 'acordes em bloco' modifica:", opts: ["As notas do motivo", "A textura — a forma como os acordes são desdobrados no tempo, criando leveza ou movimento", "A tonalidade", "O ritmo do motivo"], a: 1, fb: "Os arpejos decompõem os acordes em notas sucessivas — criando movimento e leveza (Chopin). Os acordes em bloco criam solidez e impacto (Beethoven). Mesma harmonia, mesmo motivo melódico, texturas completamente diferentes." },
  { q: "O 'contraponto' como técnica de desenvolvimento motívico consiste em:", opts: ["Repetir o motivo duas vezes", "Acrescentar uma voz independente que responde, imita ou contrasta com o motivo — enriquecendo a polifonia", "Mudar o andamento", "Inverter os intervalos"], a: 1, fb: "O contraponto acrescenta uma ou mais vozes que dialogam com o motivo principal. Esta voz pode imitá-lo (cânone), responder em movimento contrário, ou acompanhá-lo em sextas paralelas. A obra torna-se mais densa sem modificar o motivo — enriquecimento por adição, não por transformação." },
  { q: "A 'linha de baixo' como desenvolvimento motívico significa:", opts: ["Tocar o motivo no baixo", "Transformar o baixo num contraponto melódico independente — terça, sexta ou movimento contrário — que dialoga com o motivo", "Suprimir o baixo", "Dobrar o baixo à oitava"], a: 1, fb: "Em vez de simplesmente dobrar o baixo harmónico, dá-se-lhe um próprio contorno melódico — uma linha de baixo em movimento contrário ao motivo, ou em terças/sextas paralelas. Técnica muito presente em Bach (corais) e Beethoven (sonatas): enriquece a textura sem alterar o motivo." },
  { q: "Modificar as 'nuances' de um motivo (forte → piano) transforma:", opts: ["As alturas das notas", "A intensidade e o carácter expressivo — mesma melodia, impacto emocional radicalmente diferente", "O ritmo", "A tonalidade"], a: 1, fb: "O mesmo motivo tocado fortissimo é ameaçador ou triunfal; pianissimo torna-se misterioso ou terno. Beethoven explora sistematicamente esta dicotomia: apresenta o seu motivo fortissimo, depois repete-o pianissimo — dupla afirmação, duplo carácter." },
  { q: "Transpor um motivo uma oitava acima produz:", opts: ["O mesmo efeito que na oitava inferior", "Luminosidade, urgência e clareza — o registo agudo é percebido como mais brilhante e intenso", "Um abrandamento percebido", "Uma mudança de tonalidade"], a: 1, fb: "O registo agudo cria luminosidade e tensão (percebida como mais urgente psicologicamente). A oitava grave cria profundidade, gravidade, autoridade. Beethoven usa esta transformação de registo sistematicamente nos seus desenvolvimentos — mesmo motivo, registos diferentes, efeitos dramáticos contrastantes." },
  { q: "Passar de legato a staccato no mesmo motivo:", opts: ["Abranda o motivo", "Muda a articulação — o carácter torna-se incisivo, leve ou nervoso segundo o contexto, sem tocar nas alturas", "Modifica os intervalos", "Muda a harmonia"], a: 1, fb: "Legato = notas ligadas, fluxo contínuo, carácter lírico ou suave. Staccato = notas separadas, carácter vivo, leve ou incisivo. O mesmo motivo em legato parece nostálgico; em staccato, brincalhão ou urgente. A articulação é um dos parâmetros mais finos e expressivos do desenvolvimento dinâmico." },
  { q: "Mudar o 'timbre' num desenvolvimento motívico significa:", opts: ["Mudar o compositor", "Confiar o mesmo motivo a um instrumento diferente (violinos → metais, piano → orquestra) — mesma melodia, cor instrumental radicalmente diferente", "Mudar a tonalidade", "Modificar o ritmo"], a: 1, fb: "O mesmo motivo nos violinos parece lírico; nos metais, heróico; na flauta, aéreo; no piano fortissimo, percussivo. O timbre é a 'voz' do instrumento. Nos desenvolvimentos sinfónicos, Beethoven passa o mesmo motivo por diferentes famílias orquestrais — pura transformação de timbre, não de notas." },
  { q: "A 'inversão' (inversão dos intervalos) de um motivo consiste em:", opts: ["Tocar o motivo ao contrário", "Inverter cada intervalo: uma subida de terça torna-se uma descida de terça (e vice-versa)", "Repetir o motivo duas vezes mais rápido", "Transpor uma oitava"], a: 1, fb: "A inversão espelha cada intervalo. Sol–Sol–Sol–Mib (queda de terça menor) torna-se Sol–Sol–Sol–Sib (subida de terça menor). O contorno rítmico permanece idêntico; o perfil melódico é invertido. Técnica frequente nas fugas de Bach e nos desenvolvimentos de Beethoven." },
  { q: "O 'retrógrado' de um motivo é:", opts: ["O motivo tocado mais lentamente", "O motivo tocado ao contrário — da última nota para a primeira", "O motivo transposto uma oitava", "O motivo repetido duas vezes"], a: 1, fb: "O retrógrado inverte a ordem das notas: Mib–Sol–Sol–Sol é o retrógrado de Sol–Sol–Sol–Mib (Beethoven). Técnica usada por Bach nos cânones, por Beethoven e pelos serialistas. Pode parecer irreconhecível ao ouvido mas mantém coerência lógica com o material original." },
  { q: "Acrescentar 'notas de passagem' a um motivo:", opts: ["Destrói completamente o motivo", "Enriquece o contorno melódico preenchendo os saltos — o motivo original permanece reconhecível, a melodia torna-se mais fluida", "Muda o ritmo", "Muda a tonalidade"], a: 1, fb: "As notas de passagem preenchem os intervalos do motivo. Um salto de terça (Dó–Mi) torna-se um fragmento de escala (Dó–Ré–Mi). O contorno rítmico pode permanecer idêntico. O motivo é mais rico melodicamente, menos 'angular', mas a sua identidade de partida permanece percetível." },
  { q: "Uma 'transformação não rítmica' de um motivo significa:", opts: ["Conservar o ritmo idêntico mas modificar as alturas segundo a escala (marcha harmónica ou transposição)", "Mudar apenas o ritmo", "Suprimir todas as notas", "Inverter o motivo"], a: 0, fb: "A transformação não rítmica conserva o esquema rítmico do motivo mas desloca as alturas ao longo da escala (sequência tonal) ou por transposição exata (sequência real). O ritmo — frequentemente a identidade mais forte — permanece reconhecível; as alturas variam. Esta é a marcha harmónica ou sequência." },
  { q: "Porque razão inversão e retrógrado são transformações da 'família C'?", opts: ["Porque são as mais simples", "Porque transformam o contorno melódico sem necessariamente tocar no ritmo — alturas modificadas, estrutura temporal preservada", "Porque se aplicam depois das alterações rítmicas", "Porque apenas modificam a harmonia"], a: 1, fb: "Inversão e retrógrado modificam as alturas mantendo frequentemente a estrutura rítmica. Pertencem às transformações melódicas (família C). São mais radicais que a família A (harmonia) mas menos radicais que a família D (alterações rítmicas)." },
  { q: "A omissão de uma nota de um motivo:", opts: ["Destrói completamente o motivo", "Alivia o motivo — o contorno geral pode permanecer reconhecível, criando uma versão reduzida ou fragmentada", "Nunca é usada em composição", "Deve sempre ser compensada por outra nota"], a: 1, fb: "Omitir uma nota cria uma versão 'aliviada' do motivo — técnica de liquidação progressiva (termo de Schoenberg). O motivo perde progressivamente os seus traços distintivos. Beethoven usa esta técnica no final dos desenvolvimentos: o motivo fragmenta-se até se dissolver na cadência final." },
  { q: "A 'aumentação' de um motivo consiste em:", opts: ["Tocar o motivo mais forte", "Duplicar (ou triplicar) a duração de cada nota — o motivo abranda, adquire uma amplitude solene", "Transpor uma oitava", "Inverter os intervalos"], a: 1, fb: "A aumentação duplica cada duração: uma colcheia torna-se uma semínima, uma semínima torna-se uma mínima. O motivo estende-se no tempo — efeito de câmara lenta, solenidade, grandiosidade. Beethoven usa-a nos desenvolvimentos para criar um sentimento de inevitabilidade." },
  { q: "A 'diminuição' de um motivo consiste em:", opts: ["Tocar o motivo mais suave", "Dividir a duração de cada nota — o motivo acelera, torna-se nervoso ou urgente", "Suprimir notas", "Inverter o motivo"], a: 1, fb: "A diminuição divide cada duração: uma semínima torna-se uma colcheia, uma colcheia uma semicolcheia. O motivo acelera — efeito de tensão crescente, impaciência, urgência. Técnica frequente nos desenvolvimentos de fugas (Bach) e nas secções de liquidação de Beethoven." },
  { q: "A mudança de compasso (3/4 → 4/4) transforma um motivo:", opts: ["Acrescentando-lhe notas", "Mudando o seu contexto métrico — o mesmo motivo num compasso diferente cria um sentimento de leveza, desequilíbrio ou nova energia", "Modificando as suas alturas", "Duplicando a sua duração"], a: 1, fb: "Transpor um motivo de 4/4 para 3/4 dá-lhe um ar de valsa; de 3/4 para 2/4, uma energia de marcha. A barra de compasso desloca-se em relação às notas — os acentos caem noutros pontos. Chopin usa esta técnica no seu Scherzo n.º 2." },
  { q: "Porque razão as alterações rítmicas são aplicadas por último?", opts: ["Porque são mais difíceis de escrever", "Porque o ritmo é frequentemente o elemento mais distintivo do motivo — modificá-lo é a mudança mais radical, com risco de tornar o motivo irreconhecível", "Porque requerem uma orquestra", "Porque são as menos expressivas"], a: 1, fb: "O ritmo é frequentemente o ADN mais robusto de um motivo — o ta-ta-ta-TAA de Beethoven é reconhecível mesmo transposto para outra tonalidade. Tocar no ritmo arrisca perder a identidade do motivo. Por isso as alterações rítmicas vêm por último: maior poder transformativo — e maior risco." },
  { q: "A 'desregulação' rítmica de um motivo consiste em:", opts: ["Regularizar as síncopes", "Transformar os tempos fortes em síncopes — deslocar os acentos do motivo para criar tensão ou surpresa rítmica", "Duplicar a duração das notas", "Mudar o andamento"], a: 1, fb: "A desregulação cria síncopes onde o motivo original tinha tempos fortes. O efeito é de destabilização rítmica — o ouvido esperava um acento num lugar, chega deslocado. Técnica muito presente no jazz (fraseado off-beat) e nos desenvolvimentos beethovenianos." },
  { q: "A ordem correta de aplicação das 4 famílias é:", opts: ["D → C → B → A (ritmo primeiro)", "A → B → C → D (harmonia primeiro, ritmo por último)", "C → A → D → B (melódico primeiro)", "Não existe uma ordem definida"], a: 1, fb: "A ordem A–B–C–D vai de menos a mais radical: A (harmonia/acompanhamento) transforma menos a identidade do motivo; D (ritmo) transforma-a mais. Começa-se pelas transformações que deixam o motivo plenamente reconhecível, progredindo progressivamente para transformações mais profundas." },
  { q: "Para aplicar uma transformação que deixe o motivo plenamente identificável, usa-se:", opts: ["A família D (alterações rítmicas)", "A família A (harmonia e acompanhamento) — o contorno melódico e o ritmo permanecem intactos", "A família C (transformações melódicas)", "As famílias B e D em conjunto"], a: 1, fb: "A família A é a menos radical: mudar a harmonia ou a textura (arpejos, contraponto, substituição) deixa o motivo completamente reconhecível. A melodia e o ritmo — os seus dois traços mais identificáveis — permanecem intactos. É a 'recoloração' do motivo, não a sua transformação." },
  { q: "Quantas famílias de técnicas de desenvolvimento motívico existem?", opts: ["3", "4", "5", "7"], a: 1, fb: "Existem 4 famílias: A (harmonia e acompanhamento), B (disposição dinâmica), C (transformações melódicas), D (alterações rítmicas). Cada família agrupa técnicas de um grau de radicalidade semelhante e é aplicada nesta ordem — de menos a mais transformativa." },
  { q: "Em que ano Beethoven compôs a sua 5ª Sinfonia?", opts: ["1789", "1808", "1820", "1827"], a: 1, fb: "A 5ª Sinfonia de Beethoven foi concluída em 1808 (dedicada ao príncipe Lobkowitz e ao conde Razumovsky). No mesmo ano saiu a 6ª Sinfonia (Pastoral). Beethoven estava então no seu período 'heróico' — já surdo há vários anos, o que torna o seu domínio motívico ainda mais notável." },
  { q: "Beethoven está frequentemente associado a que princípio estético?", opts: ["A ornamentação barroca", "A economia de meios — construir o máximo a partir do mínimo de material motívico", "A melodia operística", "A improvisação modal"], a: 1, fb: "A economia de meios é o princípio beethoveniano por excelência: extrair o máximo do mínimo. 4 notas geram uma sinfonia. Esta abordagem contrastava com o estilo galante e ornamental dos seus predecessores. Para Beethoven, a riqueza não está na quantidade de material, mas na profundidade do seu desenvolvimento." },
  { q: "A que época compositiva pertence Beethoven?", opts: ["Barroco (1600–1750)", "Classicismo (1750–1820) — com um pé no Romantismo", "Romantismo tardio (1850–1900)", "Impressionismo (1890–1920)"], a: 1, fb: "Beethoven (1770–1827) é uma charneira: as suas primeiras obras inscrevem-se no classicismo vienense (Haydn, Mozart), mas as obras tardias (Quartetos op.132, Sonata op.111, 9ª Sinfonia) antecipam o Romantismo e mesmo o século XX. Transcende as categorias de época." },
  { q: "Schoenberg analisou notavelmente a técnica de Beethoven em:", opts: ["A Arte da Fuga", "Fundamentals of Musical Composition — tratado que formaliza a frase, o motivo, o período e as formas beethovenianas", "O Cravo Bem Temperado", "O Tratado de orquestração de Berlioz"], a: 1, fb: "Schoenberg redigiu Fundamentals of Musical Composition na UCLA nos anos 1930–40 (publicado postumamente em 1967). O seu tratado analisa sistematicamente a frase e o desenvolvimento motívico de Beethoven — paradoxalmente, Schoenberg é também o pai do dodecafonismo, que aboliu a tonalidade beethoveniana." },
  { q: "Como se reconhece um bom motivo de partida?", opts: ["Deve ser muito longo", "É curto, distintivo, memorável e suficientemente flexível para ser transformado de múltiplas formas", "Deve conter todas as notas da escala", "Deve evitar as dissonâncias"], a: 1, fb: "Um bom motivo combina brevidade (memorável), distintividade (reconhecível entre outros) e flexibilidade (transformável). Sol–Sol–Sol–Mib satisfaz os três critérios. Um motivo demasiado complexo é difícil de transformar; demasiado simples, torna-se monótono. O equilíbrio é a arte do compositor." },
  { q: "Qual é o erro mais comum com um motivo em composição?", opts: ["Usá-lo demasiado", "Repetir o motivo identicamente demasiadas vezes seguidas sem transformação — a monotonia instala-se rapidamente", "Transpô-lo para outras tonalidades", "Usá-lo em diferentes famílias instrumentais"], a: 1, fb: "A repetição pura é a tentação e a armadilha. Um motivo repetido identicamente mais de duas vezes perde o seu poder de atração. O ouvido espera variedade. A arte consiste em manter o reconhecimento (coerência) enquanto se renova (variedade) — este é o paradoxo da repetição." },
  { q: "Qual é o efeito de uma 'marcha harmónica' no desenvolvimento de um motivo?", opts: ["Suprimir o motivo", "Repetir o motivo em graus sucessivos da escala — o efeito é de expansão tonal progressiva", "Mudar apenas o andamento", "Parar o discurso musical"], a: 1, fb: "A marcha harmónica repete o motivo em cada grau da escala (I, II, III, IV...). O ouvinte percebe simultaneamente a coerência (mesmo motivo) e o movimento (mudança de altura em cada repetição). Efeito de 'progressão' ou 'escalada' muito eficaz no desenvolvimento." },
  { q: "Na improvisação de jazz, como é que o conhecimento do desenvolvimento motívico melhora o jogo?", opts: ["Permite tocar mais notas", "Fornece ferramentas para construir um discurso coerente — expor uma ideia, repeti-la/transformá-la, desenvolvê-la para um clímax, concluir", "Obriga a ficar na escala pentatónica", "Substitui o conhecimento da grelha harmónica"], a: 1, fb: "Um improvisador que domina o desenvolvimento motívico constrói um 'discurso' em vez de uma sucessão de notas. Expõe um motivo (algumas notas), repete-o e transforma-o (família A, B, C ou D), cria um clímax, depois conclui. O ouvinte segue a história. Esta é a diferença entre improvisar 'dentro' da grelha e improvisar 'através' dela." },
  { q: "A 'liquidação' de um motivo no final de uma frase (Schoenberg) produz:", opts: ["Um silêncio", "Uma dissolução progressiva do motivo — perde os seus traços distintivos um a um, sinalizando que a cadência se aproxima", "Uma modulação", "Uma mudança de andamento"], a: 1, fb: "A liquidação é a erosão progressiva do motivo no final de uma frase. Primeiro conservam-se o ritmo e a melodia, depois apenas o ritmo, depois quase nada — a frase dissolve-se na cadência. Procedimento retórico muito sofisticado de 'conclusão' que Beethoven domina perfeitamente nas suas sonatas." },
  { q: "A combinação de várias técnicas de desenvolvimento (ex. aumentação + substituição harmónica):", opts: ["É proibida em composição", "Produz transformações mais ricas e complexas — as famílias combinam-se livremente", "Só é usada no século XX", "Apaga completamente a identidade do motivo"], a: 1, fb: "As 4 famílias de técnicas combinam-se livremente. Um motivo pode ser simultaneamente transposto (família C), com harmonia substituída (família A) e tocado pianissimo (família B). As combinações criam transformações mais ricas — exatamente o que Beethoven faz nos grandes desenvolvimentos das suas sonatas e sinfonias." },
];

